
import { useState, useEffect, useCallback, useRef } from "react";

// ─── STORAGE (shared = synced across devices) ─────────────────────────────────
import { database } from "./firebase";
import { ref, set as fbSet, get, remove } from "firebase/database";

// ─── localStorage helpers (fallback when Firebase is unreachable / rules block access)
function lsGet(key) { try { const v = localStorage.getItem("lms_ls_" + key); return v ? JSON.parse(v) : null; } catch { return null; } }
function lsSet(key, val) { try { localStorage.setItem("lms_ls_" + key, JSON.stringify(val)); } catch {} }
function lsDel(key) { try { localStorage.removeItem("lms_ls_" + key); } catch {} }

// Firebase prohibits dots in key names — encode dots→commas before writing,
// decode commas→dots after reading. (Emails like "jane@x.com" use dot-keys.)
function fbEncodeKeys(obj) {
  if (!obj || typeof obj !== "object" || Array.isArray(obj)) return obj;
  const out = {};
  Object.keys(obj).forEach(k => { out[k.replace(/\./g, ",")] = obj[k]; });
  return out;
}

// Shared = true uses /shared/ path (all users), false uses /local/ path
// Architecture: localStorage = primary (instant, always works)
//               Firebase     = sync layer (best-effort, runs in background)
async function db(op, key, val, shared = false) {
  const path = shared ? `shared/${key}` : `local/${key}`;
  const dbRef = ref(database, path);

  // ── WRITE: localStorage first (guaranteed), then Firebase (best-effort) ──
  if (op === "set") {
    if (!shared) lsSet(key, val); // localStorage stores with original dot-keys
    const fbVal = fbEncodeKeys(val);  // Firebase gets comma-keys (dots forbidden)
    try { await fbSet(dbRef, fbVal); } catch (e) { console.warn("Firebase write:", e.code || e.message); }
    return val;
  }

  // ── DELETE: localStorage first (guaranteed), then Firebase (best-effort) ──
  if (op === "del") {
    if (!shared) lsDel(key); // always succeeds
    try { await remove(dbRef); } catch (e) { console.warn("Firebase delete:", e.code || e.message); }
    return true;
  }

  // ── READ: prefer Firebase (source of truth), fall back to localStorage ──
  if (op === "get") {
    try {
      const snapshot = await get(dbRef);
      let result = snapshot.exists() ? snapshot.val() : null;
      // Firebase prohibits dots in key names and silently converts them to commas.
      // Email-based keys (e.g. "jane@domain.com" → "jane@domain,com") must be decoded.
      if (result !== null && typeof result === "object" && !Array.isArray(result)) {
        const decoded = {};
        Object.keys(result).forEach(k => { decoded[k.replace(/,/g, ".")] = result[k]; });
        result = decoded;
      }
      if (result !== null && !shared) lsSet(key, result); // sync Firebase → localStorage
      return result !== null ? result : (!shared ? lsGet(key) : null);
    } catch (e) {
      console.warn("Firebase read:", e.code || e.message);
      return !shared ? lsGet(key) : null; // Firebase blocked → use localStorage
    }
  }

  // ── LIST ──
  if (op === "list") {
    try {
      const snapshot = await get(ref(database, shared ? "shared" : "local"));
      if (!snapshot.exists()) return [];
      return Object.keys(snapshot.val()).filter(k => k.startsWith(key));
    } catch { return []; }
  }
}

