function fmt(iso) { try { return new Date(iso).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" }); } catch { return "—"; } }
function exportCSV(rows, filename) {
  const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g, '""')}"`).join(",")).join("\n");
  const a = Object.assign(document.createElement("a"), { href: `data:text/csv;charset=utf-8,${encodeURIComponent(csv)}`, download: filename });
  a.click();
}
function daysLeft(joinDate) {
  if (!joinDate) return DEADLINE_DAYS;
  const diff = DEADLINE_DAYS - Math.floor((Date.now() - new Date(joinDate)) / 86400000);
  return Math.max(0, diff);
}
function deadlineColor(days) {
  if (days <= 3) return "#f87171";
  if (days <= 7) return "#fbbf24";
  return "#4ade80";
}
// Print certificate in a new window
// ─── PDF CERTIFICATE GENERATOR (jsPDF) ────────────────────────────────────────
// White-mode, Today Style 2100 CI (gold #C9A84C), professional typography
async function generateCertificatePDF({ recipientName, programmeTitle, bodyText, signatoryName, signatoryTitle, completionDate, logoUrl }) {
  const { jsPDF } = window.jspdf || {};
  if (!jsPDF) { alert("PDF library not loaded — please refresh the page and try again."); return; }

  const doc = new jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });
  const W = 297, H = 210;

  // ── Palette ──
  const gold   = [201, 168, 76];
  const goldLt = [220, 195, 120];
  const navy   = [18,  18,  26];
  const gray1  = [90,  85,  75];
  const gray2  = [140, 133, 118];
  const gray3  = [195, 188, 175];
  const white  = [255, 255, 255];

  // ── Background ──
  doc.setFillColor(...white);
  doc.rect(0, 0, W, H, "F");

  // ── Subtle background watermark text ──
  doc.setFont("times", "italic");
  doc.setFontSize(110);
  doc.setTextColor(248, 246, 240);
  doc.text("TS2100", W / 2, H / 2 + 14, { align: "center" });

  // ── Outer double-rule border ──
  doc.setDrawColor(...gold);
  doc.setLineWidth(1.2);
  doc.rect(7, 7, W - 14, H - 14);
  doc.setLineWidth(0.3);
  doc.rect(11, 11, W - 22, H - 22);

  // ── Corner ornaments (L-brackets) ──
  const co = 7, cs = 18; // corner offset, corner size
  doc.setDrawColor(...gold);
  doc.setLineWidth(1.0);
  [[co, co], [W - co, co], [co, H - co], [W - co, H - co]].forEach(([x, y], i) => {
    const sx = i % 2 === 0 ? 1 : -1;
    const sy = i < 2 ? 1 : -1;
    doc.line(x, y, x + sx * cs, y);
    doc.line(x, y, x, y + sy * cs);
    // Small diamond dot at corner tip
    doc.setFillColor(...gold);
    doc.circle(x, y, 0.8, "F");
  });

  // ── Top ornamental row ──
  const centerX = W / 2;
  // Thin gold line with centre break for logo area
  doc.setDrawColor(...goldLt);
  doc.setLineWidth(0.3);
  doc.line(20, 28, centerX - 32, 28);
  doc.line(centerX + 32, 28, W - 20, 28);

  // ── Company name (text-based, since logo is external) ──
  doc.setFont("helvetica", "bold");
  doc.setFontSize(9);
  doc.setTextColor(...gold);
  doc.setCharSpace(3);
  doc.text("TODAY STYLE 2100", centerX, 24, { align: "center" });
  doc.setCharSpace(0);
  doc.setFont("helvetica", "normal");
  doc.setFontSize(6.5);
  doc.setTextColor(...gray2);
  doc.text("EST. 1977  ·  ARCHITECTURAL & INTERIOR HARDWARE", centerX, 28.5, { align: "center" });

  // ── Decorative divider with diamond ──
  const divY = 38;
  doc.setDrawColor(...gold);
  doc.setLineWidth(0.5);
  doc.line(centerX - 55, divY, centerX - 6, divY);
  doc.line(centerX + 6, divY, centerX + 55, divY);
  doc.setFillColor(...gold);
  // Diamond shape
  const dm = 2.5;
  doc.lines([[dm, -dm], [dm, dm], [-dm, dm], [-dm, -dm]], centerX - dm, divY, [1, 1], "F", true);

  // ── "CERTIFICATE OF COMPLETION" label ──
  doc.setFont("helvetica", "normal");
  doc.setFontSize(8);
  doc.setTextColor(...gray1);
  doc.setCharSpace(3.5);
  doc.text("CERTIFICATE OF COMPLETION", centerX, 46, { align: "center" });
  doc.setCharSpace(0);

  // Thin underline
  doc.setDrawColor(...gray3);
  doc.setLineWidth(0.2);
  doc.line(centerX - 40, 48, centerX + 40, 48);

  // ── "This is to certify that" ──
  doc.setFont("times", "italic");
  doc.setFontSize(11);
  doc.setTextColor(...gray1);
  doc.text("This is to certify that", centerX, 58, { align: "center" });

  // ── Recipient Name (large, elegant) ──
  doc.setFont("times", "italic");
  doc.setFontSize(34);
  doc.setTextColor(...navy);
  doc.text(recipientName, centerX, 76, { align: "center" });

  // Gold rule under name
  doc.setDrawColor(...gold);
  doc.setLineWidth(0.6);
  const nameW = doc.getTextWidth(recipientName);
  const ruleW = Math.min(nameW + 20, 120);
  doc.line(centerX - ruleW / 2, 80, centerX + ruleW / 2, 80);

  // ── Body text (wrapped) ──
  doc.setFont("times", "normal");
  doc.setFontSize(10);
  doc.setTextColor(...gray1);
  const lines = doc.splitTextToSize(bodyText, 180);
  doc.text(lines, centerX, 90, { align: "center", lineHeightFactor: 1.5 });

  // ── Programme title (gold) ──
  doc.setFont("times", "italic");
  doc.setFontSize(11.5);
  doc.setTextColor(...gold);
  doc.text(programmeTitle, centerX, 110, { align: "center" });

  // ── Bottom section divider ──
  doc.setDrawColor(...gray3);
  doc.setLineWidth(0.2);
  doc.line(20, 124, W - 20, 124);

  // ── Bottom three columns: Signature | Seal | Date ──
  const bY = 148; // baseline for signature lines / content

  // LEFT — Signatory
  doc.setDrawColor(...gray3);
  doc.setLineWidth(0.4);
  doc.line(28, bY - 2, 100, bY - 2);
  doc.setFont("helvetica", "bold");
  doc.setFontSize(9);
  doc.setTextColor(...navy);
  doc.text(signatoryName, 64, bY + 5, { align: "center" });
  doc.setFont("helvetica", "normal");
  doc.setFontSize(7.5);
  doc.setTextColor(...gray2);
  doc.text(signatoryTitle, 64, bY + 10, { align: "center" });

  // CENTRE — Gold seal badge
  const sealX = centerX, sealY = bY - 12;
  // Outer ring
  doc.setDrawColor(...gold);
  doc.setLineWidth(1.2);
  doc.circle(sealX, sealY, 14);
  doc.setLineWidth(0.4);
  doc.circle(sealX, sealY, 11.5);
  // Inner fill
  doc.setFillColor(250, 247, 240);
  doc.circle(sealX, sealY, 11, "F");
  // Trophy emoji text
  doc.setFont("helvetica", "bold");
  doc.setFontSize(18);
  doc.setTextColor(...gold);
  doc.text("★", sealX, sealY + 3, { align: "center" });
  // "CERTIFIED" text around seal
  doc.setFont("helvetica", "bold");
  doc.setFontSize(5.5);
  doc.setCharSpace(1.5);
  doc.setTextColor(...gold);
  doc.text("CERTIFIED", sealX, sealY + 17.5, { align: "center" });
  doc.setCharSpace(0);

  // RIGHT — Date of Completion
  doc.setDrawColor(...gray3);
  doc.setLineWidth(0.4);
  doc.line(197, bY - 2, 269, bY - 2);
  doc.setFont("helvetica", "normal");
  doc.setFontSize(7);
  doc.setTextColor(...gray2);
  doc.setCharSpace(1.5);
  doc.text("DATE OF COMPLETION", 233, bY + 3, { align: "center" });
  doc.setCharSpace(0);
  doc.setFont("helvetica", "bold");
  doc.setFontSize(11);
  doc.setTextColor(...navy);
  doc.text(completionDate, 233, bY + 10, { align: "center" });

  // ── Bottom company tagline ──
  doc.setFont("helvetica", "normal");
  doc.setFontSize(6.5);
  doc.setTextColor(...gray3);
  doc.setCharSpace(1.5);
  doc.text("TODAY STYLE 2100  ·  HARDWARE EXCELLENCE PROGRAMME", centerX, H - 13, { align: "center" });
  doc.setCharSpace(0);

  // ── Save ──
  const safeName = recipientName.replace(/[^a-zA-Z0-9 ]/g, "").trim().replace(/ +/g, "_");
  doc.save(`Certificate_${safeName}_TS2100.pdf`);
}

function printCertificate(html) {
  const win = window.open("", "_blank");
  win.document.write(`<!DOCTYPE html><html><head><title>Certificate</title><style>
    @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400&display=swap');
    * { margin:0; padding:0; box-sizing:border-box; }
    body { font-family: 'Cormorant Garamond', serif; background: #fff; }
    @media print { body { -webkit-print-color-adjust: exact; print-color-adjust: exact; } }
  </style></head><body>${html}</body></html>`);
  win.document.close();
  setTimeout(() => { win.focus(); win.print(); }, 600);
}


