function SpecialistTrackView({ lang, user, trackId, G, specialistProgress, onUpdateProgress, onBack, theme, setTheme }) {
  const track = SPECIALIST_TRACKS.find(t => t.id === trackId);
  const [activeLessonId, setActiveLessonId] = useState(null);
  const [quizMode, setQuizMode] = useState(false);
  const [quizState, setQuizState] = useState({ qi: 0, answers: [] });
  const [quizResult, setQuizResult] = useState(null);

  // Timer effect for timed quiz — hooks must be declared before any early return
  const secsPerQ = track?.secsPerQ || 60;
  const [timeLeft, setTimeLeft] = useState(secsPerQ);
  const timerRef = useRef(null);

  useEffect(() => {
    if (!track || !quizMode || quizResult || !activeLesson) return;
    const answered = quizState.answers[quizState.qi] !== undefined;
    if (answered) return;
    setTimeLeft(secsPerQ);
    timerRef.current = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timerRef.current);
          // Time out — mark as wrong (no answer = -1)
          const na = [...quizState.answers];
          if (na[quizState.qi] === undefined) na[quizState.qi] = -1;
          const totalQ = activeLesson.quiz.length;
          if (quizState.qi === totalQ - 1) {
            setQuizState(s => ({ ...s, answers: na }));
            finishQuiz(activeLesson);
          } else {
            setQuizState(s => ({ qi: s.qi + 1, answers: na }));
          }
          return secsPerQ;
        }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, [quizState.qi, quizMode, quizResult]); // eslint-disable-line react-hooks/exhaustive-deps

  if (!track) return null;

  const prog = specialistProgress[user.email + "_" + trackId] || {};
  const certified = prog.certified;

  const activeLesson = track.lessons.find(l => l.id === activeLessonId);

  const T = (obj) => (obj && (obj[lang] || obj.en)) || "";

  const finishQuiz = (lesson) => {
    const { answers } = quizState;
    const score = answers.filter((a, i) => a === lesson.quiz[i].answer).length;
    const total = lesson.quiz.length;
    const pct = score / total;
    const passed = pct >= track.passThreshold;

    // Update progress
    const key = user.email + "_" + trackId;
    const updated = {
      ...specialistProgress,
      [key]: {
        ...(specialistProgress[key] || {}),
        ["l_" + lesson.id]: { completed: true, score, passed, date: new Date().toISOString().split("T")[0] }
      }
    };

    // Check if ALL lessons passed → certify
    const allPassed = track.lessons.every(l => {
      if (l.id === lesson.id) return passed;
      return updated[key]["l_" + l.id]?.passed;
    });

    if (allPassed) {
      updated[key].certified = true;
      updated[key].certDate = new Date().toISOString().split("T")[0];
    }

    onUpdateProgress(updated);
    setQuizResult({ score, total, pct: Math.round(pct * 100), passed, certified: allPassed });
  };

  // Quiz view
  if (quizMode && activeLesson) {
    if (quizResult) {
      return (
        <div style={{ maxWidth: 600, margin: "60px auto", padding: "0 24px", textAlign: "center", animation: "fadeUp 0.3s ease" }}>
          <div style={{ fontSize: 56, marginBottom: 16 }}>{quizResult.certified ? "🎖️" : quizResult.passed ? "✅" : "❌"}</div>
          <h2 style={{ fontSize: 28, color: quizResult.passed ? "#4ade80" : "#f87171", marginBottom: 8 }}>
            {quizResult.certified ? (lang === "en" ? "SPECIALIST CERTIFIED!" : "ได้รับการรับรองผู้เชี่ยวชาญ!") : quizResult.passed ? (lang === "en" ? "Lesson Passed!" : "ผ่านบทเรียน!") : (lang === "en" ? "Not Passed" : "ไม่ผ่าน")}
          </h2>
          <div style={{ fontSize: 48, fontWeight: 700, color: quizResult.passed ? "#4ade80" : "#f87171", marginBottom: 8 }}>
            {quizResult.pct}%
          </div>
          <p style={{ color: G.muted, marginBottom: 8 }}>{quizResult.score}/{quizResult.total} {lang === "en" ? "correct" : "ถูก"} · {lang === "en" ? "Pass threshold: " : "เกณฑ์ผ่าน: "}{Math.round(track.passThreshold * 100)}%</p>
          {quizResult.certified && (
            <div style={{ padding: "16px 24px", background: `${track.color}15`, border: `1px solid ${track.color}50`, borderRadius: 10, margin: "20px 0", color: track.color, fontWeight: 600 }}>
              🏅 {lang === "en" ? `You are now a certified ${track.brand} Specialist!` : `คุณได้รับการรับรองเป็น ${track.brand} Specialist แล้ว!`}
            </div>
          )}
          <div style={{ display: "flex", gap: 12, justifyContent: "center", marginTop: 24 }}>
            {!quizResult.passed && (
              <button onClick={() => { clearInterval(timerRef.current); setTimeLeft(secsPerQ); setQuizState({ qi: 0, answers: [] }); setQuizResult(null); }}
                style={{ padding: "10px 24px", background: "transparent", border: `1px solid ${G.border}`, borderRadius: 6, color: G.muted, fontSize: 14 }}>
                {lang === "en" ? "Retry Quiz" : "ทำซ้ำ"}
              </button>
            )}
            <button onClick={() => { clearInterval(timerRef.current); setQuizMode(false); setQuizResult(null); setQuizState({ qi: 0, answers: [] }); }}
              style={{ padding: "10px 24px", background: track.color, border: "none", borderRadius: 6, color: "#000", fontWeight: 700, fontSize: 14 }}>
              {lang === "en" ? "Back to Track" : "กลับไป Track"}
            </button>
          </div>
        </div>
      );
    }

    const q = activeLesson.quiz[quizState.qi];
    const totalQ = activeLesson.quiz.length;
    const answered = quizState.answers[quizState.qi] !== undefined;
    const timerPct = (timeLeft / secsPerQ) * 100;
    const timerColor = timeLeft > 20 ? track.color : timeLeft > 10 ? "#f59e0b" : "#ef4444";
    return (
      <div style={{ maxWidth: 700, margin: "40px auto", padding: "0 24px", animation: "fadeUp 0.2s ease" }}>
        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 16 }}>
          <button onClick={() => { clearInterval(timerRef.current); setQuizMode(false); }} style={{ padding: "6px 14px", background: "transparent", border: `1px solid ${G.border}`, borderRadius: 6, color: G.muted, fontSize: 13 }}>← {lang === "en" ? "Back" : "กลับ"}</button>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 12, color: track.color }}>{track.icon} {track.brand} Specialist Quiz</div>
            <div style={{ fontSize: 13, color: G.muted }}>{T(activeLesson.title)}</div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 22, fontWeight: 700, color: timerColor, lineHeight: 1 }}>{timeLeft}</div>
            <div style={{ fontSize: 10, color: G.muted }}>sec</div>
          </div>
          <div style={{ fontSize: 12, color: G.muted, minWidth: 40, textAlign: "right" }}>{quizState.qi + 1}/{totalQ}</div>
        </div>

        {/* Progress bar (question progress) */}
        <div style={{ height: 3, background: G.border, borderRadius: 2, marginBottom: 6 }}>
          <div style={{ height: "100%", width: `${((quizState.qi + 1) / totalQ) * 100}%`, background: track.color, borderRadius: 2, transition: "width 0.3s" }} />
        </div>

        {/* Timer bar */}
        <div style={{ height: 4, background: G.inputBg, borderRadius: 2, marginBottom: 20, position: "relative" }}>
          <div style={{ height: "100%", width: `${timerPct}%`, background: timerColor, borderRadius: 2, transition: "width 1s linear" }} />
          <div style={{ position: "absolute", right: 0, top: "50%", transform: "translateY(-50%)", fontSize: 9, color: timerColor, paddingRight: 2 }}>{lang === "en" ? "TIME" : "เวลา"}</div>
        </div>

        <div style={{ background: G.card, border: `1px solid ${G.border}`, borderRadius: 12, padding: "24px 28px", marginBottom: 16 }}>
          <div style={{ fontSize: 11, color: G.muted, marginBottom: 10, letterSpacing: "0.08em" }}>
            {lang === "en" ? "QUESTION" : "คำถาม"} {quizState.qi + 1} · {Math.round(track.passThreshold * 100)}% {lang === "en" ? "required to pass" : "ต้องผ่าน"}
          </div>
          <p style={{ fontSize: 16, color: G.text, lineHeight: 1.7, marginBottom: 22 }}>{T(q.q)}</p>
          <div style={{ display: "flex", flexDirection: "column", gap: 9 }}>
            {T(q.options).map((opt, oi) => {
              const isSelected = quizState.answers[quizState.qi] === oi;
              const isCorrect = oi === q.answer;
              const timedOut = quizState.answers[quizState.qi] === -1;
              let bg = G.inputBg, border = G.border, color = G.text;
              if (answered) {
                if (isCorrect) { bg = "#0a1a0a"; border = "#4ade80"; color = "#4ade80"; }
                else if (isSelected && !timedOut) { bg = "#1a0a0a"; border = "#f87171"; color = "#f87171"; }
              }
              return (
                <button key={oi}
                  onClick={() => {
                    if (answered) return;
                    clearInterval(timerRef.current);
                    const na = [...quizState.answers]; na[quizState.qi] = oi;
                    if (quizState.qi === totalQ - 1) {
                      setQuizState({ ...quizState, answers: na });
                      finishQuiz(activeLesson);
                    } else {
                      setTimeout(() => { setTimeLeft(secsPerQ); setQuizState({ qi: quizState.qi + 1, answers: na }); }, 800);
                      setQuizState({ ...quizState, answers: na });
                    }
                  }}
                  style={{ padding: "13px 16px", background: bg, border: `1px solid ${border}`, borderRadius: 8, color, fontSize: 15, textAlign: "left", cursor: answered ? "default" : "pointer", transition: "all 0.2s" }}>
                  {opt}
                </button>
              );
            })}
          </div>
          {answered && quizState.answers[quizState.qi] === -1 && (
            <p style={{ fontSize: 13, color: "#f87171", marginTop: 12 }}>⏱ {lang === "en" ? "Time up — correct answer shown in green." : "หมดเวลา — คำตอบที่ถูกต้องแสดงในสีเขียว"}</p>
          )}
        </div>
      </div>
    );
  }

  // Lesson content view
  if (activeLesson && !quizMode) {
    const lessonProg = prog["l_" + activeLesson.id] || {};
    return (
      <div style={{ maxWidth: 740, margin: "0 auto", padding: "40px 24px", animation: "fadeUp 0.3s ease" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 24 }}>
          <button onClick={() => setActiveLessonId(null)} style={{ padding: "6px 14px", background: "transparent", border: `1px solid ${G.border}`, borderRadius: 6, color: G.muted, fontSize: 13 }}>← {lang === "en" ? "Back" : "กลับ"}</button>
          <div>
            <div style={{ fontSize: 11, color: track.color, letterSpacing: "0.1em", textTransform: "uppercase" }}>{track.icon} {track.brand} Specialist</div>
            <div style={{ fontSize: 17, color: G.goldLight, fontWeight: 600 }}>{T(activeLesson.title)}</div>
          </div>
        </div>
        <div style={{ background: G.card, border: `1px solid ${G.border}`, borderRadius: 10, padding: "28px 32px", marginBottom: 28 }}>
          <div className="lesson-content" dangerouslySetInnerHTML={{ __html: T(activeLesson.content) }} style={{ color: G.text, fontSize: 16, lineHeight: 1.9 }} />
        </div>
        <button onClick={() => { setQuizMode(true); setQuizState({ qi: 0, answers: [] }); setQuizResult(null); }}
          style={{ padding: "14px 36px", background: track.color, border: "none", borderRadius: 6, color: "#000", fontWeight: 700, fontSize: 15, letterSpacing: "0.06em", cursor: "pointer" }}>
          {lessonProg.passed ? (lang === "en" ? "RETAKE QUIZ" : "ทำซ้ำ") : (lang === "en" ? "START QUIZ →" : "เริ่มแบบทดสอบ →")}
        </button>
        {lessonProg.passed && <span style={{ fontSize: 13, color: "#4ade80", marginLeft: 16 }}>✓ {lang === "en" ? `Best: ${lessonProg.score}/${activeLesson.quiz.length}` : `ดีที่สุด: ${lessonProg.score}/${activeLesson.quiz.length}`}</span>}
      </div>
    );
  }

  // Track overview (lesson list)
  return (
    <div style={{ maxWidth: 860, margin: "0 auto", padding: "40px 24px", animation: "fadeUp 0.3s ease" }}>
      <button onClick={onBack} style={{ padding: "7px 16px", background: "transparent", border: `1px solid ${G.border}`, borderRadius: 6, color: G.muted, fontSize: 14, marginBottom: 28, cursor: "pointer" }}>
        ← {lang === "en" ? "All Tracks" : "ทุก Track"}
      </button>

      {/* Track header */}
      <div style={{ display: "flex", alignItems: "flex-start", gap: 20, marginBottom: 32, padding: "24px", background: `${track.color}10`, border: `1px solid ${track.color}40`, borderRadius: 12, flexWrap: "wrap" }}>
        <div style={{ width: 64, height: 64, borderRadius: "50%", background: `${track.color}20`, border: `2px solid ${track.color}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 30, flexShrink: 0 }}>{track.icon}</div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 22, fontWeight: 700, color: track.color, marginBottom: 4 }}>{track.brand} Specialist</div>
          <div style={{ fontSize: 13, color: G.muted, marginBottom: 8 }}>{track.origin} · {track.tier} · Pass: {Math.round(track.passThreshold * 100)}%</div>
          <p style={{ fontSize: 14, color: G.text, lineHeight: 1.6 }}>{track.tagline}</p>
        </div>
        {certified && (
          <div style={{ padding: "10px 20px", background: "#0a1a0a", border: "1px solid #4ade80", borderRadius: 8, textAlign: "center" }}>
            <div style={{ fontSize: 24 }}>🎖️</div>
            <div style={{ fontSize: 11, color: "#4ade80", fontWeight: 700 }}>CERTIFIED</div>
            <div style={{ fontSize: 10, color: G.muted }}>{prog.certDate}</div>
          </div>
        )}
      </div>

      {/* Lessons */}
      <h3 style={{ fontSize: 11, color: G.muted, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 16 }}>{lang === "en" ? "Lessons" : "บทเรียน"}</h3>
      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
        {track.lessons.map((lesson, idx) => {
          const lp = prog["l_" + lesson.id] || {};
          return (
            <div key={lesson.id} onClick={() => setActiveLessonId(lesson.id)}
              style={{ display: "flex", alignItems: "center", gap: 16, padding: "18px 22px", background: G.card, border: `1px solid ${lp.passed ? "#4ade8044" : G.border}`, borderRadius: 10, cursor: "pointer" }}
              onMouseEnter={e => e.currentTarget.style.borderColor = track.color + "60"}
              onMouseLeave={e => e.currentTarget.style.borderColor = lp.passed ? "#4ade8044" : G.border}>
              <div style={{ width: 36, height: 36, borderRadius: "50%", background: lp.passed ? "#0a1a0a" : G.inputBg, border: `2px solid ${lp.passed ? "#4ade80" : G.border}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 15, fontWeight: 700, color: lp.passed ? "#4ade80" : G.muted, flexShrink: 0 }}>
                {lp.passed ? "✓" : idx + 1}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 15, color: G.text, fontWeight: 600 }}>{T(lesson.title)}</div>
                <div style={{ fontSize: 12, color: G.muted, marginTop: 3 }}>
                  {lesson.quiz.length} {lang === "en" ? "questions" : "คำถาม"} · {lang === "en" ? "80% to pass" : "ต้องผ่าน 80%"}
                  {lp.passed && <span style={{ marginLeft: 12, color: "#4ade80" }}>✓ {lp.score}/{lesson.quiz.length}</span>}
                </div>
              </div>
              <span style={{ fontSize: 18, color: track.color }}>→</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default function App() {
  const [lang, setLang] = useState("en");
  const [themeMode, setThemeMode] = useState(() => { try { return localStorage.getItem("lms_theme") || "dark"; } catch { return "dark"; } });
  const [fontMode, setFontMode] = useState(() => { try { return localStorage.getItem("lms_font") || "cormorant"; } catch { return "cormorant"; } });
  const [view, setView] = useState("boot");
  const [currentUser, setCurrentUser] = useState(null);
  const [users, setUsers] = useState({});
  const [modules, setModules] = useState(DEFAULT_MODULES);
  const [progress, setProgress] = useState({});
  const [auditLog, setAuditLog] = useState([]);
  const [pwResets, setPwResets] = useState([]);
  const [aiSuggestions, setAiSuggestions] = useState([]);
  const [quizFeedback, setQuizFeedback] = useState([]);
  const [customRoles, setCustomRoles] = useState(DEFAULT_ROLES);
  const [announcements, setAnnouncements] = useState([]);
  const [regRequests, setRegRequests] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [active, setActive] = useState({ moduleId: null, lessonId: null });
  const [specialistProgress, setSpecialistProgress] = useState({});
  const [activeSpecialist, setActiveSpecialist] = useState(null); // { trackId }
  const [quizState, setQuizState] = useState(null);
  const [preQuizMode, setPreQuizMode] = useState(false);
  const [toast, setToast] = useState(null);
  const [syncing, setSyncing] = useState(false);
  const [isOnline, setIsOnline] = useState(true);
  const [showOnboarding, setShowOnboarding] = useState(false);

  const G = makeTheme(themeMode);
  const setTheme = (mode) => { setThemeMode(mode); try { localStorage.setItem("lms_theme", mode); } catch {} };
  const setFont  = (mode) => { setFontMode(mode);  try { localStorage.setItem("lms_font",  mode); } catch {} };

  const T = useCallback((obj) => (obj && (obj[lang] || obj.en)) || "", [lang]);
  const toast_ = useCallback((msg, type = "ok") => { setToast({ msg, type }); setTimeout(() => setToast(null), 3500); }, []);

  useEffect(() => {
    const on = () => setIsOnline(true);
    const off = () => setIsOnline(false);
    window.addEventListener("online", on);
    window.addEventListener("offline", off);
    return () => { window.removeEventListener("online", on); window.removeEventListener("offline", off); };
  }, []);

  useEffect(() => {
    (async () => {
      const localUsers = await db("get", "lms_users") || {};
      const localProgress = await db("get", "lms_progress") || {};
      const localModules = await db("get", "lms_modules");
      const localAudit = await db("get", "lms_audit") || [];
      const localPwResets = await db("get", "lms_pwresets") || [];
      const localAiSugg = await db("get", "lms_aisugg") || [];
      const localQuizFb = await db("get", "lms_quizfeedback") || [];
      const localRoles = await db("get", "lms_roles");
      const localAnnouncements = await db("get", "lms_announcements") || [];
      const localRegReqs = await db("get", "lms_regreqs") || [];
      const localNotifications = await db("get", "lms_notifications") || [];
      const session = await db("get", "lms_session");
      setUsers(localUsers); setProgress(localProgress);
      setAuditLog(localAudit); setPwResets(localPwResets); setAiSuggestions(localAiSugg); setQuizFeedback(localQuizFb);
      setAnnouncements(localAnnouncements); setRegRequests(localRegReqs); setNotifications(localNotifications);
      if (localModules) setModules(localModules);
      const localSP = await db("get", "lms_specialist") || {};
      setSpecialistProgress(localSP);
      if (localRoles) setCustomRoles(localRoles);
      let mergedUsers = localUsers, mergedProgress = localProgress;
      try {
        const sU = await db("get", "lms_users", null, true);
        const sP = await db("get", "lms_progress", null, true);
        const sM = await db("get", "lms_modules", null, true);
        const sA = await db("get", "lms_audit", null, true);
        const sR = await db("get", "lms_pwresets", null, true);
        const sS = await db("get", "lms_aisugg", null, true);
        if (sU) {
          // Merge Firebase users WITH local users — locally-added users are never lost.
          // Firebase wins per-email (deletions from another device are respected),
          // but any email only in localStorage (added offline) is kept.
          const merged = { ...mergedUsers, ...sU };
          mergedUsers = merged;
          setUsers(merged);
          await db("set", "lms_users", merged); // keep localStorage in sync
          try { await db("set", "lms_users", merged, true); } catch {} // push offline additions to Firebase
        }
        if (sP) {
          // Same merge logic for progress — don't lose offline quiz completions
          const mergedProg = { ...mergedProgress, ...sP };
          setProgress(mergedProg);
          await db("set", "lms_progress", mergedProg);
        }
        if (sM) { setModules(sM); await db("set", "lms_modules", sM); }
        if (sA) { setAuditLog(sA); await db("set", "lms_audit", sA); }
        if (sR) { setPwResets(sR); await db("set", "lms_pwresets", sR); }
        if (sS) { setAiSuggestions(sS); await db("set", "lms_aisugg", sS); }
        const sSP = await db("get", "lms_specialist", null, true);
        if (sSP) { setSpecialistProgress(sSP); await db("set", "lms_specialist", sSP); }
        const sRoles = await db("get", "lms_roles", null, true);
        if (sRoles) { setCustomRoles(sRoles); await db("set", "lms_roles", sRoles); }
        const sAnn = await db("get", "lms_announcements", null, true);
        if (sAnn) { setAnnouncements(sAnn); await db("set", "lms_announcements", sAnn); }
        const sRegR = await db("get", "lms_regreqs", null, true);
        if (sRegR) { setRegRequests(sRegR); await db("set", "lms_regreqs", sRegR); }
      } catch { }
      if (session === "admin") { setCurrentUser({ role: "admin" }); setView("admin"); }
      else if (session && mergedUsers[session]) { setCurrentUser(mergedUsers[session]); setView("dashboard"); }
      else {
        // ── SSO: check Firebase Auth (portal login) ──
        try {
          const { getAuth } = await import("firebase/auth");
          const auth = getAuth();
          const fbUser = auth.currentUser;
          if (fbUser && fbUser.email) {
            const email = fbUser.email.toLowerCase();
            if (mergedUsers[email]) {
              await db("set", "lms_session", email);
              setCurrentUser(mergedUsers[email]); setView("dashboard"); return;
            }
            // Auto-create LMS account from portal auth
            const newUser = { name: fbUser.displayName || email.split("@")[0], email, password: "portal-sso", role: "user", joinDate: new Date().toISOString(), deadlineDate: new Date(Date.now() + 30 * 86400000).toISOString() };
            const updated = { ...mergedUsers, [email]: newUser };
            setUsers(updated); await db("set", "lms_users", updated); try { await db("set", "lms_users", updated, true); } catch {}
            await db("set", "lms_session", email);
            setCurrentUser(newUser); setView("dashboard"); return;
          }
        } catch (e) { console.warn("SSO check:", e.message); }
        setView("login");
      }
    })();
  }, []);

  async function syncShared(key, val) {
    setSyncing(true);
    try { await db("set", key, val, true); } catch { }
    await db("set", key, val);
    setSyncing(false);
  }

  // ── LOG SHORTCUT ──
  const log = useCallback(async (currentLog, entry) => {
    const updated = await addAuditLog(currentLog, entry);
    setAuditLog(updated);
    return updated;
  }, []);

  async function login(email, password) {
    if (email.trim() === "admin" && password === ADMIN_PASS) {
      await db("set", "lms_session", "admin");
      await log(auditLog, { actor: "admin", actorName: "Admin", action: AUDIT_ACTIONS.LOGIN_OK, detail: "Admin signed in" });
      setCurrentUser({ role: "admin" }); setView("admin"); return;
    }
    const u = users[email.trim()];
    if (!u) {
      await log(auditLog, { actor: email.trim(), actorName: email.trim(), action: AUDIT_ACTIONS.LOGIN_FAIL, detail: `Account not found: ${email.trim()}` });
      return toast_(lang === "en" ? "Account not found." : "ไม่พบบัญชี", "err");
    }
    if (u.password !== password) {
      await log(auditLog, { actor: u.email, actorName: u.name, action: AUDIT_ACTIONS.LOGIN_FAIL, detail: "Incorrect password" });
      return toast_(lang === "en" ? "Incorrect password." : "รหัสผ่านไม่ถูกต้อง", "err");
    }
    await db("set", "lms_session", email.trim());
    await log(auditLog, { actor: u.email, actorName: u.name, action: AUDIT_ACTIONS.LOGIN_OK, detail: "Signed in" });
    // Show onboarding checklist for first-ever login
    const onboardKey = "lms_onboarded_" + email.trim();
    const isFirstLogin = !localStorage.getItem(onboardKey);
    if (isFirstLogin) { localStorage.setItem(onboardKey, "1"); }
    setCurrentUser(u); setView("dashboard");
    if (isFirstLogin) setShowOnboarding(true);
  }

  async function logout() {
    if (currentUser && currentUser.role !== "admin") {
      await log(auditLog, { actor: currentUser.email, actorName: currentUser.name, action: AUDIT_ACTIONS.LOGOUT, detail: "Signed out" });
    }
    await db("set", "lms_session", null);
    setCurrentUser(null); setView("login");
  }

  async function createUser(data) {
    if (users[data.email]) return toast_(lang === "en" ? "Email already exists." : "อีเมลนี้มีอยู่แล้ว", "err");
    const newUser = { ...data, joinDate: new Date().toISOString(), deadlineDate: new Date(Date.now() + DEADLINE_DAYS * 86400000).toISOString() };
    const updated = { ...users, [data.email]: newUser };
    setUsers(updated); await syncShared("lms_users", updated);
    await log(auditLog, { actor: "admin", actorName: "Admin", action: AUDIT_ACTIONS.USER_CREATE, detail: `Created account for ${data.name} (${data.email})` });
    toast_(lang === "en" ? `Account created for ${data.name}` : `สร้างบัญชีสำหรับ ${data.name} สำเร็จ`);
  }

  async function deleteUser(email) {
    const name = users[email]?.name || email;
    const updated = { ...users }; delete updated[email];
    setUsers(updated); await syncShared("lms_users", updated);
    await log(auditLog, { actor: "admin", actorName: "Admin", action: AUDIT_ACTIONS.USER_DELETE, detail: `Deleted account: ${name} (${email})` });
    toast_(lang === "en" ? "User removed." : "ลบผู้ใช้แล้ว");
  }

  async function updateUser(oldEmail, data) {
    const existing = users[oldEmail] || {};
    const newEmail = (data.email || "").trim() || oldEmail;
    const updated = { ...users };
    if (newEmail !== oldEmail) delete updated[oldEmail];
    // Only update password if a new one was provided
    const newPw = data.password?.trim() ? data.password.trim() : existing.password;
    updated[newEmail] = { ...existing, ...data, email: newEmail, password: newPw };
    setUsers(updated); await syncShared("lms_users", updated);
    if (currentUser?.email === oldEmail) setCurrentUser(updated[newEmail]);
    await log(auditLog, { actor: "admin", actorName: "Admin", action: AUDIT_ACTIONS.USER_CREATE, detail: `Updated account: ${data.name || existing.name} (${newEmail})` });
    toast_(lang === "en" ? "Account updated." : "อัปเดตบัญชีแล้ว");
  }

  async function extendDeadline(email, days) {
    const u = users[email]; if (!u) return;
    const current = u.deadlineDate ? new Date(u.deadlineDate) : new Date();
    const extended = new Date(current.getTime() + days * 86400000);
    const updated = { ...users, [email]: { ...u, deadlineDate: extended.toISOString() } };
    setUsers(updated); await syncShared("lms_users", updated);
    await log(auditLog, { actor: "admin", actorName: "Admin", action: "deadline_extended", detail: `Extended deadline for ${u.name} by ${days} days → ${fmt(extended.toISOString())}` });
    toast_(lang === "en" ? `Deadline extended by ${days} days.` : `ขยายเวลา ${days} วัน`);
  }

  async function resetProgress(email) {
    const name = users[email]?.name || email;
    const updated = { ...progress };
    Object.keys(updated).filter(k => k.startsWith(email + "_")).forEach(k => delete updated[k]);
    setProgress(updated); await syncShared("lms_progress", updated);
    await log(auditLog, { actor: "admin", actorName: "Admin", action: AUDIT_ACTIONS.PROGRESS_RESET, detail: `Reset progress for ${name} (${email})` });
    toast_(lang === "en" ? "Progress reset." : "รีเซ็ตความคืบหน้าแล้ว");
  }

  async function saveModules(updated) {
    setModules(updated); await syncShared("lms_modules", updated);
    await log(auditLog, { actor: "admin", actorName: "Admin", action: AUDIT_ACTIONS.CONTENT_EDIT, detail: "Module content updated" });
    toast_(lang === "en" ? "Content saved & synced." : "บันทึกและซิงค์เนื้อหาแล้ว");
  }

  // ── PASSWORD RESET REQUESTS ──
  async function submitPwResetRequest(email, message) {
    const u = users[email.trim()];
    if (!u) return toast_(lang === "en" ? "No account found for that email." : "ไม่พบบัญชีสำหรับอีเมลนี้", "err");
    const existing = pwResets.find(r => r.email === email.trim() && r.status === "pending");
    if (existing) return toast_(lang === "en" ? "A request is already pending for this account." : "มีคำขออยู่แล้วสำหรับบัญชีนี้", "err");
    const req = { id: Date.now(), email: email.trim(), name: u.name, message, status: "pending", ts: new Date().toISOString() };
    const updated = [req, ...pwResets];
    setPwResets(updated); await syncShared("lms_pwresets", updated);
    await log(auditLog, { actor: email.trim(), actorName: u.name, action: AUDIT_ACTIONS.PW_RESET_REQ, detail: `Password reset requested${message ? `: "${message}"` : ""}` });
    toast_(lang === "en" ? "Request sent to admin. They will reset your password." : "ส่งคำขอถึงแอดมินแล้ว");
  }

  async function resolvePasswordReset(reqId, newPassword) {
    const req = pwResets.find(r => r.id === reqId);
    if (!req) return;
    // Update user password
    const updatedUsers = { ...users, [req.email]: { ...users[req.email], password: newPassword } };
    setUsers(updatedUsers); await syncShared("lms_users", updatedUsers);
    // Mark request resolved
    const updatedResets = pwResets.map(r => r.id === reqId ? { ...r, status: "resolved", resolvedTs: new Date().toISOString(), newPassword } : r);
    setPwResets(updatedResets); await syncShared("lms_pwresets", updatedResets);
    await log(auditLog, { actor: "admin", actorName: "Admin", action: AUDIT_ACTIONS.PW_RESET_DONE, detail: `Password reset for ${req.name} (${req.email})` });
    toast_(lang === "en" ? `Password updated for ${req.name}` : `อัปเดตรหัสผ่านสำหรับ ${req.name} แล้ว`);
  }

  async function dismissPwReset(reqId) {
    const updatedResets = pwResets.map(r => r.id === reqId ? { ...r, status: "dismissed" } : r);
    setPwResets(updatedResets); await syncShared("lms_pwresets", updatedResets);
    toast_(lang === "en" ? "Request dismissed." : "ปฏิเสธคำขอแล้ว");
  }

  // ── AI SUGGESTIONS ──
  async function submitAiSuggestion(suggestion) {
    // suggestion: { id, ts, author, moduleId, lessonId, moduleName, lessonName, field, proposed, rationale, status:"pending" }
    const updated = [suggestion, ...aiSuggestions];
    setAiSuggestions(updated); await syncShared("lms_aisugg", updated);
    await log(auditLog, { actor: suggestion.author || "specialist", actorName: suggestion.author || "Specialist", action: "ai_suggestion", detail: `AI content suggestion for ${suggestion.moduleName} → ${suggestion.lessonName}` });
  }

  async function approveAiSuggestion(suggId) {
    const sugg = aiSuggestions.find(s => s.id === suggId);
    if (!sugg) return;
    // Snapshot the lesson before overwriting (content versioning)
    const prevMod = modules.find(m => m.id === sugg.moduleId);
    const prevLesson = prevMod?.lessons.find(l => l.id === sugg.lessonId);
    const versionEntry = { id: suggId, ts: new Date().toISOString(), author: sugg.author, snapshot: prevLesson ? prevLesson[sugg.field] : null, field: sugg.field, lessonId: sugg.lessonId, moduleId: sugg.moduleId, moduleName: sugg.moduleName, lessonName: sugg.lessonName };
    const localVersions = await db("get", "lms_versions") || [];
    const updatedVersions = [versionEntry, ...localVersions].slice(0, 50); // keep last 50
    await db("set", "lms_versions", updatedVersions);
    // Apply: update the lesson content field
    const updated = modules.map(m => m.id !== sugg.moduleId ? m : {
      ...m, lessons: m.lessons.map(l => l.id !== sugg.lessonId ? l : {
        ...l, [sugg.field]: typeof sugg.proposed === "object"
          ? { ...l[sugg.field], ...sugg.proposed }
          : sugg.proposed
      })
    });
    setModules(updated); await syncShared("lms_modules", updated);
    const updatedSugg = aiSuggestions.map(s => s.id === suggId ? { ...s, status: "approved", resolvedTs: new Date().toISOString() } : s);
    setAiSuggestions(updatedSugg); await syncShared("lms_aisugg", updatedSugg);
    await log(auditLog, { actor: "admin", actorName: "Admin", action: "ai_approved", detail: `Approved AI suggestion for ${sugg.moduleName} → ${sugg.lessonName}` });
    toast_(lang === "en" ? "Content updated from AI suggestion." : "อัปเดตเนื้อหาจาก AI แล้ว");
  }

  async function rejectAiSuggestion(suggId) {
    const updatedSugg = aiSuggestions.map(s => s.id === suggId ? { ...s, status: "rejected", resolvedTs: new Date().toISOString() } : s);
    setAiSuggestions(updatedSugg); await syncShared("lms_aisugg", updatedSugg);
    toast_(lang === "en" ? "Suggestion rejected." : "ปฏิเสธคำแนะนำแล้ว");
  }

  async function submitQuizFeedback(fb) {
    const updated = [...quizFeedback, fb];
    setQuizFeedback(updated);
    await db("set", "lms_quizfeedback", updated);
    try { await db("set", "lms_quizfeedback", updated, true); } catch {}
    toast_(lang === "en" ? "Feedback submitted — thank you!" : "ส่งความคิดเห็นแล้ว ขอบคุณ!", "ok");
  }

  async function saveCustomRoles(roles) {
    setCustomRoles(roles);
    await syncShared("lms_roles", roles);
    toast_(lang === "en" ? "Roles saved." : "บันทึกตำแหน่งแล้ว");
  }

  // ── ANNOUNCEMENTS ──
  async function createAnnouncement(data) {
    const ann = { id: Date.now(), ...data, ts: new Date().toISOString(), likes: [] };
    const updated = [ann, ...announcements];
    setAnnouncements(updated); await syncShared("lms_announcements", updated);
    // Push notification to all users
    const notif = { id: Date.now() + 1, type: "announcement", title: data.title, body: data.body, annId: ann.id, ts: new Date().toISOString(), read: false };
    const updN = [notif, ...notifications];
    setNotifications(updN);
    await db("set", "lms_notifications", updN);
    try { await db("set", "lms_notifications", updN, true); } catch {}
    toast_(lang === "en" ? "Announcement posted!" : "โพสต์ประกาศแล้ว!");
  }

  async function deleteAnnouncement(id) {
    const updated = announcements.filter(a => a.id !== id);
    setAnnouncements(updated); await syncShared("lms_announcements", updated);
    toast_(lang === "en" ? "Announcement deleted." : "ลบประกาศแล้ว");
  }

  async function likeAnnouncement(id) {
    if (!currentUser) return;
    const email = currentUser.email || currentUser.role;
    const updated = announcements.map(a => {
      if (a.id !== id) return a;
      const already = (a.likes || []).includes(email);
      return { ...a, likes: already ? a.likes.filter(e => e !== email) : [...(a.likes || []), email] };
    });
    setAnnouncements(updated); await syncShared("lms_announcements", updated);
  }

  // ── REGISTRATION REQUESTS ──
  async function submitRegRequest(data) {
    const existing = regRequests.find(r => r.email === data.email && r.status === "pending");
    if (existing) return toast_(lang === "en" ? "A request is already pending for this email." : "มีคำขอรออยู่แล้ว", "err");
    const req = { id: Date.now(), ...data, status: "pending", ts: new Date().toISOString() };
    const updated = [req, ...regRequests];
    setRegRequests(updated); await syncShared("lms_regreqs", updated);
    toast_(lang === "en" ? "Registration request sent! Admin will review and approve." : "ส่งคำขอสมัครแล้ว ผู้ดูแลจะตรวจสอบและอนุมัติ");
  }

  async function approveRegRequest(id) {
    const req = regRequests.find(r => r.id === id);
    if (!req) return;
    if (users[req.email]) return toast_(lang === "en" ? "Email already registered." : "อีเมลนี้ลงทะเบียนแล้ว", "err");
    await createUser({ name: req.name, email: req.email, password: req.password, department: req.department, role: "Trainee", employeeId: "" });
    const updated = regRequests.map(r => r.id === id ? { ...r, status: "approved", resolvedTs: new Date().toISOString() } : r);
    setRegRequests(updated); await syncShared("lms_regreqs", updated);
    toast_(lang === "en" ? `${req.name} approved and account created!` : `อนุมัติ ${req.name} และสร้างบัญชีแล้ว!`);
  }

  async function rejectRegRequest(id) {
    const updated = regRequests.map(r => r.id === id ? { ...r, status: "rejected", resolvedTs: new Date().toISOString() } : r);
    setRegRequests(updated); await syncShared("lms_regreqs", updated);
    toast_(lang === "en" ? "Registration request rejected." : "ปฏิเสธคำขอสมัครแล้ว");
  }

  // ── NOTIFICATIONS ──
  async function markNotificationRead(id) {
    const updated = notifications.map(n => n.id === id ? { ...n, read: true } : n);
    setNotifications(updated);
    await db("set", "lms_notifications", updated);
  }

  async function markAllNotificationsRead() {
    const updated = notifications.map(n => ({ ...n, read: true }));
    setNotifications(updated);
    await db("set", "lms_notifications", updated);
  }

  const getStatus = (email, moduleId, lessonId) => progress[`${email}_${moduleId}_${lessonId}`] || null;

  const getUserTotals = (email) => {
    const total = modules.reduce((a, m) => a + m.lessons.length, 0);
    const done = modules.reduce((a, m) => a + m.lessons.filter(l => getStatus(email, m.id, l.id)?.completed).length, 0);
    const avgScore = (() => {
      const scores = [];
      modules.forEach(m => m.lessons.forEach(l => { const s = getStatus(email, m.id, l.id); if (s?.completed) scores.push((s.score / l.quiz.length) * 100); }));
      return scores.length ? Math.round(scores.reduce((a, b) => a + b, 0) / scores.length) : 0;
    })();
    return { done, total, pct: total ? Math.round((done / total) * 100) : 0, avgScore };
  };

  // ── LEARNING PATHS: module lock check ──
  const isModuleLocked = useCallback((mod, email) => {
    if (!mod.unlockAfter || mod.unlockAfter.length === 0) return false;
    return mod.unlockAfter.some(reqId => {
      const reqMod = modules.find(m => m.id === reqId);
      if (!reqMod) return false;
      const done = reqMod.lessons.filter(l => getStatus(email, reqMod.id, l.id)?.completed).length;
      return done < reqMod.lessons.length; // not 100% done
    });
  }, [modules, progress, getStatus]);

  async function recordProgress(moduleId, lessonId, score, isPreQuiz = false) {
    const key = `${currentUser.email}_${moduleId}_${lessonId}`;
    const existing = progress[key];
    const lesson = modules.find(m => m.id === moduleId)?.lessons.find(l => l.id === lessonId);
    const passed = score >= Math.ceil((lesson?.quiz.length || 10) * 0.7);
    const wasCompleted = existing?.completed;
    const updated = { ...progress, [key]: { score, date: new Date().toISOString(), completed: passed || wasCompleted, attempts: (existing?.attempts || 0) + 1, skippedLesson: isPreQuiz && passed } };
    setProgress(updated); await syncShared("lms_progress", updated);
    const modTitle = modules.find(m => m.id === moduleId)?.title?.en || moduleId;
    const lessonTitle = lesson?.title?.en || lessonId;
    await log(auditLog, {
      actor: currentUser.email, actorName: currentUser.name,
      action: isPreQuiz && passed ? AUDIT_ACTIONS.QUIZ_SKIP : passed ? AUDIT_ACTIONS.QUIZ_PASS : AUDIT_ACTIONS.QUIZ_FAIL,
      detail: `${isPreQuiz ? "[Pre-quiz] " : ""}${modTitle} → ${lessonTitle} | Score: ${score}/${lesson?.quiz.length} (${Math.round(score/(lesson?.quiz.length||1)*100)}%)${isPreQuiz && passed ? " — lesson skipped" : ""}`
    });
    // Check if full training now complete
    const newPct = updated ? Math.round(Object.keys(updated).filter(k => k.startsWith(currentUser.email + "_") && updated[k].completed).length / modules.reduce((a, m) => a + m.lessons.length, 0) * 100) : 0;
    if (newPct === 100 && !wasCompleted) {
      const updatedUsers = { ...users, [currentUser.email]: { ...currentUser, completionDate: new Date().toISOString() } };
      setUsers(updatedUsers); await syncShared("lms_users", updatedUsers);
    }
    return { passed };
  }

  // Style injection — theme + font aware
  useEffect(() => {
    const existing = document.getElementById("lms-global-style");
    if (existing) existing.remove();
    const fontCfg = FONTS.find(f => f.id === fontMode) || FONTS[0];
    const style = document.createElement("style");
    style.id = "lms-global-style";
    style.textContent = `
      @import url('${fontCfg.importUrl}');
      * { box-sizing: border-box; margin: 0; padding: 0; }
      body { font-family: ${fontCfg.stack}; font-size: ${fontCfg.size}; font-weight: 500; -webkit-font-smoothing: antialiased; }
      @keyframes fadeUp { from { opacity:0; transform:translateY(14px); } to { opacity:1; transform:translateY(0); } }
      @keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
      @keyframes spin { to { transform: rotate(360deg); } }
      button { cursor: pointer; font-family: inherit; font-size: inherit; font-weight: 500; }
      input, textarea, select { font-family: inherit; font-size: inherit; font-weight: 500; }
      p, div, span, td, th, label { font-weight: 500; }
      strong { font-weight: 700; }
    `;
    document.head.appendChild(style);
    return () => { const s = document.getElementById("lms-global-style"); if (s) s.remove(); };
  }, [fontMode]);

  // Apply body background from theme
  useEffect(() => {
    document.body.style.background = G.bodyBg;
  }, [G.bodyBg]);

  // ── RENDER ──
  if (view === "boot") return (
    <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", background: G.bodyBg }}>
      <div style={{ textAlign: "center" }}>
        <img src={LOGO} alt="" style={{ height: 36, marginBottom: 20, opacity: 0.6, filter: G.mode === "light" ? "invert(1)" : "none" }} />
        <div style={{ width: 28, height: 28, border: `3px solid ${G.border}`, borderTop: `3px solid ${G.gold}`, borderRadius: "50%", margin: "0 auto", animation: "spin 1s linear infinite" }} />
      </div>
    </div>
  );

  if (view === "login") return (
    <LoginView lang={lang} setLang={setLang} G={G} theme={themeMode} setTheme={setTheme} onLogin={login} onForgotPassword={submitPwResetRequest} onRegister={submitRegRequest} toast={toast} />
  );

  if (view === "specialist") return (
    <SpecialistHub
      lang={lang} setLang={setLang} user={currentUser} G={G} T={T}
      specialistProgress={specialistProgress} theme={themeMode} setTheme={setTheme}
      onStartTrack={(trackId) => { setActiveSpecialist({ trackId }); setView("specialist-track"); }}
      onBack={() => setView("dashboard")}
      onLogout={async () => { await db("del","lms_session"); setCurrentUser(null); setView("login"); }}
    />
  );

  if (view === "specialist-track") return (
    <SpecialistTrackView
      lang={lang} user={currentUser} trackId={activeSpecialist?.trackId} G={G}
      specialistProgress={specialistProgress} theme={themeMode} setTheme={setTheme}
      onBack={() => setView("specialist")}
      onUpdateProgress={async (updated) => {
        setSpecialistProgress(updated);
        await db("set","lms_specialist",updated);
        try { await db("set","lms_specialist",updated,true); } catch {}
      }}
    />
  );

  if (view === "dashboard") return (
    <>
      <GlobalStyles G={G} />
      {toast && <Toast msg={toast.msg} type={toast.type} />}
      {showOnboarding && <OnboardingModal lang={lang} user={currentUser} modules={modules} G={G} onClose={() => setShowOnboarding(false)} />}
      <DashboardView lang={lang} setLang={setLang} user={currentUser} users={users} modules={modules} getStatus={getStatus}
        getUserTotals={getUserTotals} isModuleLocked={isModuleLocked} T={T} G={G} theme={themeMode} setTheme={setTheme} font={fontMode} setFont={setFont} customRoles={customRoles}
        onSpecialist={() => setView("specialist")}
        specialistProgress={specialistProgress}
        onSubmitAiSuggestion={submitAiSuggestion}
        announcements={announcements}
        onLikeAnnouncement={likeAnnouncement}
        onDeleteAnnouncement={deleteAnnouncement}
        onCreateAnnouncement={createAnnouncement}
        notifications={notifications}
        onMarkNotificationRead={markNotificationRead}
        onMarkAllNotificationsRead={markAllNotificationsRead}
        onLesson={(mId, lId, startPreQuiz) => {
          const mod = modules.find(m => m.id === mId);
          if (isModuleLocked(mod, currentUser.email)) {
            log(auditLog, { actor: currentUser.email, actorName: currentUser.name, action: AUDIT_ACTIONS.MODULE_LOCKED, detail: `Attempted locked module: ${mod?.title?.en}` });
            return toast_(lang === "en" ? "Complete prerequisite modules first." : "โปรดสำเร็จโมดูลก่อนหน้าก่อน", "err");
          }
          setActive({ moduleId: mId, lessonId: lId });
          setPreQuizMode(!!startPreQuiz);
          setView(startPreQuiz ? "quiz" : "lesson");
          if (startPreQuiz) {
            const lesson = mod?.lessons.find(l => l.id === lId);
            if (lesson) {
              let quizArr = [...lesson.quiz];
              // Shuffle question order if enabled
              if (lesson.randomizeQuestions) {
                for (let i = quizArr.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [quizArr[i], quizArr[j]] = [quizArr[j], quizArr[i]]; }
              }
              const shuffled = quizArr.map(q => {
                const order = q.options.en.map((_, i) => i);
                for (let i = order.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [order[i], order[j]] = [order[j], order[i]]; }
                return { ...q, options: { en: order.map(i => q.options.en[i]), th: order.map(i => q.options.th[i]) }, answer: order.indexOf(q.answer) };
              });
              setQuizState({ qi: 0, answers: [], shuffledQuiz: shuffled });
            }
          }
        }}
        onLogout={logout} />
    </>
  );

  if (view === "lesson") {
    const mod = modules.find(m => m.id === active.moduleId);
    const lesson = mod?.lessons.find(l => l.id === active.lessonId);
    if (!lesson) { setView("dashboard"); return null; }
    return (
      <>
        <GlobalStyles G={G} />
        {toast && <Toast msg={toast.msg} type={toast.type} />}
        <LessonView lang={lang} lesson={lesson} mod={mod} T={T} G={G} theme={themeMode} setTheme={setTheme} status={getStatus(currentUser.email, active.moduleId, active.lessonId)}
          onBack={() => setView("dashboard")} onQuiz={() => {
            let quizArr = [...lesson.quiz];
            if (lesson.randomizeQuestions) {
              for (let i = quizArr.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [quizArr[i], quizArr[j]] = [quizArr[j], quizArr[i]]; }
            }
            const shuffled = quizArr.map(q => {
              const order = q.options.en.map((_, i) => i);
              for (let i = order.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [order[i], order[j]] = [order[j], order[i]]; }
              return { ...q, options: { en: order.map(i => q.options.en[i]), th: order.map(i => q.options.th[i]) }, answer: order.indexOf(q.answer) };
            });
            setPreQuizMode(false);
            setQuizState({ qi: 0, answers: [], shuffledQuiz: shuffled });
            setView("quiz");
          }} />
      </>
    );
  }

  if (view === "quiz") {
    const mod = modules.find(m => m.id === active.moduleId);
    const lesson = mod?.lessons.find(l => l.id === active.lessonId);
    if (!lesson) { setView("dashboard"); return null; }
    return (
      <>
        <GlobalStyles G={G} />
        <QuizView lang={lang} lesson={{ ...lesson, quiz: quizState.shuffledQuiz || lesson.quiz }} moduleTitle={mod?.title?.en} T={T} G={G} theme={themeMode} setTheme={setTheme}
          isPreQuiz={preQuizMode}
          quizState={quizState} setQuizState={setQuizState}
          onComplete={async (score) => { const r = await recordProgress(active.moduleId, active.lessonId, score, preQuizMode); return r; }}
          onViewLesson={() => { setPreQuizMode(false); setView("lesson"); }}
          onBack={() => setView("dashboard")} user={currentUser} onSubmitFeedback={submitQuizFeedback} />
      </>
    );
  }

  if (view === "admin") return (
    <>
      <GlobalStyles G={G} />
      {toast && <Toast msg={toast.msg} type={toast.type} />}
      {syncing && <div style={{ position: "fixed", top: 0, left: 0, right: 0, height: 2, background: G.gold, zIndex: 999 }} />}
      <AdminView lang={lang} setLang={setLang} users={users} modules={modules} progress={progress}
        getStatus={getStatus} getUserTotals={getUserTotals} auditLog={auditLog} pwResets={pwResets}
        aiSuggestions={aiSuggestions} customRoles={customRoles}
        T={T} G={G} theme={themeMode} setTheme={setTheme} font={fontMode} setFont={setFont}
        onCreateUser={createUser} onDeleteUser={deleteUser} onResetProgress={resetProgress} onUpdateUser={updateUser} onExtendDeadline={extendDeadline}
        onSaveModules={saveModules} onLogout={logout} isOnline={isOnline}
        onResolvePasswordReset={resolvePasswordReset} onDismissPwReset={dismissPwReset}
        onSubmitAiSuggestion={submitAiSuggestion} onApproveAiSuggestion={approveAiSuggestion} onRejectAiSuggestion={rejectAiSuggestion}
        onSaveCustomRoles={saveCustomRoles} quizFeedback={quizFeedback} onClearQuizFeedback={async (updated) => { setQuizFeedback(updated); await db("set","lms_quizfeedback",updated); try { await db("set","lms_quizfeedback",updated,true); } catch {} }}
        announcements={announcements} onCreateAnnouncement={createAnnouncement} onDeleteAnnouncement={deleteAnnouncement}
        regRequests={regRequests} onApproveRegRequest={approveRegRequest} onRejectRegRequest={rejectRegRequest}
        specialistProgress={specialistProgress} getUserTotals={getUserTotals} />
    </>
  );
  return null;
}

// ─── TOAST ────────────────────────────────────────────────────────────────────
function Toast({ msg, type }) {
  return (
    <div style={{ position: "fixed", bottom: 28, right: 28, zIndex: 9999, padding: "12px 20px", background: type === "err" ? "#1a0a0a" : "#0a1a0a", border: `1px solid ${type === "err" ? "#7f1d1d" : "#166534"}`, borderRadius: 8, color: type === "err" ? "#f87171" : "#4ade80", fontSize: 13, animation: "fadeUp 0.25s ease", boxShadow: "0 4px 24px rgba(0,0,0,0.5)", maxWidth: 340 }}>
      {msg}
    </div>
  );
}

// ─── THEME TOGGLE ─────────────────────────────────────────────────────────────
function ThemeToggle({ theme, setTheme, G }) {
  const modes = [
    { id: "dark",     icon: "🌙", label: "Dark" },
    { id: "light",    icon: "☀️",  label: "Light" },
    { id: "contrast", icon: "⚡", label: "High Contrast" },
  ];
  return (
    <div style={{ display: "flex", gap: 2, background: G.card, border: `1px solid ${G.border}`, borderRadius: 8, padding: 3 }}>
      {modes.map(m => (
        <button key={m.id} onClick={() => setTheme(m.id)} title={m.label}
          style={{
            padding: "5px 10px", borderRadius: 5, border: "none",
            background: theme === m.id ? G.gold : "transparent",
            color: theme === m.id ? "#0c0c0c" : G.muted,
            fontSize: 14, fontWeight: theme === m.id ? 700 : 500,
            transition: "all 0.15s",
          }}>
          {m.icon}
        </button>
      ))}
    </div>
  );
}

// ─── FONT SELECTOR ────────────────────────────────────────────────────────────
function FontSelector({ font, setFont, G }) {
  const [open, setOpen] = useState(false);
  const current = FONTS.find(f => f.id === font) || FONTS[0];
  return (
    <div style={{ position: "relative" }}>
      <button onClick={() => setOpen(o => !o)} title="Change font"
        style={{ padding: "5px 12px", background: open ? G.gold + "22" : "transparent", border: `1px solid ${G.border}`, borderRadius: 8, color: G.muted, fontSize: 13, display: "flex", alignItems: "center", gap: 5 }}>
        <span style={{ fontWeight: 700 }}>Aa</span>
        <span style={{ fontSize: 10 }}>▾</span>
      </button>
      {open && (
        <div style={{ position: "absolute", top: "calc(100% + 6px)", right: 0, background: G.card, border: `1px solid ${G.border}`, borderRadius: 10, padding: 8, zIndex: 200, minWidth: 200, boxShadow: G.shadow }}>
          <div style={{ fontSize: 10, color: G.muted, letterSpacing: "0.1em", textTransform: "uppercase", padding: "4px 8px 8px" }}>Font Style</div>
          {FONTS.map(f => (
            <button key={f.id} onClick={() => { setFont(f.id); setOpen(false); }}
              style={{ display: "flex", alignItems: "center", justifyContent: "space-between", width: "100%", padding: "8px 12px", background: font === f.id ? G.gold + "22" : "transparent", border: "none", borderRadius: 6, color: font === f.id ? G.gold : G.text, textAlign: "left", gap: 8 }}>
              <div>
                <div style={{ fontFamily: f.stack, fontSize: 14, fontWeight: 600 }}>{f.label}</div>
                <div style={{ fontSize: 10, color: G.muted, marginTop: 1 }}>{f.preview}</div>
              </div>
              {font === f.id && <span style={{ color: G.gold, fontSize: 12 }}>✓</span>}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

