// ─── SPECIALIST KNOWLEDGE INTERVIEW (dashboard card for ai_interview users) ─────
function SpecialistInterviewCard({ lang, user, modules, T, G, onSubmit }) {
  const [open, setOpen] = useState(false);
  const [screen, setScreen] = useState("setup"); // setup | interview
  const [selectedMod, setSelectedMod] = useState("");
  const [selectedLesson, setSelectedLesson] = useState("");
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [extracted, setExtracted] = useState(null);
  const chatEndRef = useRef(null);
  useEffect(() => { chatEndRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages]);

  const SYSTEM = `You are a learning content assistant for Today Style 2100, a Bangkok-based architectural hardware company founded in 1977. You are interviewing a product specialist to capture their expertise and convert it into structured lesson content.
Your job:
1. Ask focused questions to deeply understand what the specialist knows
2. After enough information (usually 4-8 exchanges), synthesize what you've learned into a structured lesson update
3. Output a JSON block at the end of your final synthesis message in this exact format (no markdown fences, raw JSON on its own line):
SUGGESTION_JSON:{"field":"blocks","proposed":[{"id":1,"type":"text","en":"...","th":""},{"id":2,"type":"heading","en":"...","th":""}],"rationale":"Brief explanation"}
Rules: Be conversational and encouraging. Ask one or two questions at a time. Build the Thai (th) field as empty string. Only output SUGGESTION_JSON when you have enough for a complete lesson update.`;

  const selMod = modules.find(m => m.id === selectedMod);
  const selLesson = selMod?.lessons.find(l => l.id === selectedLesson);
  const canStart = selectedMod && selectedLesson;

  const startInterview = () => {
    if (!canStart) return;
    const welcome = `Hello ${user.name}! I'm here to capture your expertise on "${T(selLesson.title)}" from ${T(selMod.title)}.\n\nLet's start: In your own words, what's the most important thing a sales executive needs to understand about this topic that the current lesson might be missing or could explain better?`;
    setMessages([{ role: "assistant", content: welcome }]);
    setExtracted(null);
    setScreen("interview");
  };

  const sendMessage = async () => {
    if (!input.trim() || loading) return;
    const userMsg = { role: "user", content: input.trim() };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages); setInput(""); setLoading(true);
    try {
      const contextMsg = { role: "user", content: `[Context: Specialist "${user.name}" updating "${T(selLesson.title)}" in "${T(selMod.title)}". Current content summary: ${selLesson.content?.en?.slice(0, 300)}...]` };
      const anthropicKey = (() => { try { return localStorage.getItem("lms_anthropic_key") || ""; } catch { return ""; } })();
      if (!anthropicKey) {
        setMessages(prev => [...prev, { role: "assistant", content: "⚠️ No Anthropic API key configured. Please go to Admin → Settings and enter your API key to enable AI features." }]);
        setLoading(false);
        return;
      }
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": anthropicKey,
          "anthropic-version": "2023-06-01",
          "anthropic-dangerous-direct-browser-access": "true"
        },
        body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, system: SYSTEM, messages: [contextMsg, ...newMessages.map(m => ({ role: m.role, content: m.content }))] })
      });
      if (!response.ok) {
        const errData = await response.json().catch(() => ({}));
        const errMsg = errData?.error?.message || `API error ${response.status}`;
        throw new Error(errMsg);
      }
      const data = await response.json();
      const text = data.content?.map(c => c.text || "").join("") || "Sorry, I couldn't get a response.";
      const jsonMatch = text.match(/SUGGESTION_JSON:(\{.+\})/s);
      let displayText = text;
      if (jsonMatch) {
        try { setExtracted(JSON.parse(jsonMatch[1])); displayText = text.replace(/SUGGESTION_JSON:\{.+\}/s, "").trim() + "\n\n✅ Content update prepared — use 'Submit for Review' to send it to the admin."; } catch {}
      }
      setMessages(prev => [...prev, { role: "assistant", content: displayText }]);
    } catch { setMessages(prev => [...prev, { role: "assistant", content: "Connection error. Please try again." }]); }
    setLoading(false);
  };

  const submitForReview = async () => {
    if (!extracted) return;
    const sugg = { id: Date.now(), ts: new Date().toISOString(), author: user.name, moduleId: selectedMod, lessonId: selectedLesson, moduleName: T(selMod.title), lessonName: T(selLesson.title), field: extracted.field || "blocks", proposed: extracted.proposed, rationale: extracted.rationale || "", transcript: messages.slice(-20), status: "pending" };
    await onSubmit(sugg);
    setOpen(false); setScreen("setup"); setMessages([]); setExtracted(null); setSelectedMod(""); setSelectedLesson("");
  };

  if (!open) return (
    <div onClick={() => setOpen(true)}
      style={{ background: "linear-gradient(135deg, #07091a 0%, #0c1228 60%, #0a0d1e 100%)", border: "1.5px solid #2a4090", borderRadius: 12, padding: "20px 24px", marginBottom: 20, cursor: "pointer", display: "flex", alignItems: "center", gap: 18, boxShadow: "0 0 24px rgba(96,165,250,0.07)" }}
      onMouseEnter={e => { e.currentTarget.style.borderColor = "#4a70d0"; e.currentTarget.style.boxShadow = "0 0 32px rgba(96,165,250,0.14)"; }}
      onMouseLeave={e => { e.currentTarget.style.borderColor = "#2a4090"; e.currentTarget.style.boxShadow = "0 0 24px rgba(96,165,250,0.07)"; }}>
      {/* Icon */}
      <div style={{ width: 52, height: 52, borderRadius: 12, background: "linear-gradient(135deg, #1a3080, #0d1e50)", border: "1px solid #2a4090", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, flexShrink: 0 }}>🎙️</div>
      {/* Text */}
      <div style={{ flex: 1 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
          <div style={{ fontSize: 10, color: "#a78bfa", letterSpacing: "0.14em", textTransform: "uppercase", fontWeight: 700 }}>
            {lang === "en" ? "⭐ Specialist Role — AI Feature" : "⭐ บทบาทผู้เชี่ยวชาญ — ฟีเจอร์ AI"}
          </div>
        </div>
        <div style={{ fontSize: 16, color: "#bdd6ff", fontWeight: 700, marginBottom: 4 }}>
          {lang === "en" ? "Knowledge Interview with Claude" : "สัมภาษณ์ความรู้กับ Claude"}
        </div>
        <div style={{ fontSize: 12, color: "#4a6898", lineHeight: 1.5 }}>
          {lang === "en"
            ? `Your expertise shapes the training, ${user.name.split(" ")[0]}. Chat with Claude to improve lesson content — all suggestions go to admin for review before publishing.`
            : `ความเชี่ยวชาญของคุณช่วยพัฒนาการฝึกอบรม ${user.name.split(" ")[0]} พูดคุยกับ Claude เพื่อปรับปรุงเนื้อหา — ข้อเสนอทั้งหมดจะรอการอนุมัติก่อนเผยแพร่`}
        </div>
      </div>
      {/* CTA */}
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 4, flexShrink: 0 }}>
        <div style={{ padding: "8px 16px", background: "linear-gradient(135deg, #1a3080, #2a50c0)", border: "1px solid #4a70e0", borderRadius: 8, color: "#93c5fd", fontSize: 13, fontWeight: 700, whiteSpace: "nowrap" }}>
          {lang === "en" ? "Start Interview →" : "เริ่มสัมภาษณ์ →"}
        </div>
      </div>
    </div>
  );

  return (
    <div style={{ background: "#080c14", border: "1px solid #1a3060", borderRadius: 12, marginBottom: 20, overflow: "hidden" }}>
      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "14px 20px", borderBottom: "1px solid #1a3060", background: "#0a0f1a" }}>
        <div style={{ fontSize: 22 }}>🎙️</div>
        <div style={{ flex: 1 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div style={{ fontSize: 13, color: "#93c5fd", fontWeight: 600 }}>{lang === "en" ? "Knowledge Interview with Claude" : "สัมภาษณ์ความรู้กับ Claude"}</div>
            <div style={{ fontSize: 9, color: "#a78bfa", background: "#1a1040", border: "1px solid #4a30a0", borderRadius: 4, padding: "2px 6px", letterSpacing: "0.1em", textTransform: "uppercase", fontWeight: 700 }}>
              {lang === "en" ? "Specialist" : "ผู้เชี่ยวชาญ"}
            </div>
          </div>
          {screen === "interview" && <div style={{ fontSize: 11, color: "#4a6080" }}>{selMod?.icon} {T(selMod?.title)} → {T(selLesson?.title)}</div>}
        </div>
        {screen === "interview" && extracted && (
          <button onClick={submitForReview} style={{ padding: "7px 14px", background: "#0a1a0a", border: "1px solid #4ade80", borderRadius: 6, color: "#4ade80", fontSize: 12, fontWeight: 600 }}>
            ✓ {lang === "en" ? "Submit for Review" : "ส่งตรวจสอบ"}
          </button>
        )}
        {screen === "interview" && (
          <button onClick={() => setScreen("setup")} style={{ padding: "6px 12px", background: "transparent", border: "1px solid #1a3060", borderRadius: 5, color: "#4a6080", fontSize: 12 }}>← {lang === "en" ? "Back" : "กลับ"}</button>
        )}
        <button onClick={() => setOpen(false)} style={{ background: "transparent", border: "none", color: "#4a6080", fontSize: 18, cursor: "pointer" }}>✕</button>
      </div>

      {screen === "setup" && (
        <div style={{ padding: 20 }}>
          <div style={{ marginBottom: 14 }}>
            <label style={{ display: "block", fontSize: 10, color: "#4a6080", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 6 }}>{lang === "en" ? "Module" : "โมดูล"}</label>
            <select value={selectedMod} onChange={e => { setSelectedMod(e.target.value); setSelectedLesson(""); }}
              style={{ width: "100%", padding: "9px 12px", background: "#0a0f1a", border: "1px solid #1a3060", borderRadius: 6, color: selectedMod ? "#c9d8f0" : "#4a6080", fontSize: 14, outline: "none" }}>
              <option value="">{lang === "en" ? "— Select module —" : "— เลือกโมดูล —"}</option>
              {modules.map(m => <option key={m.id} value={m.id}>{m.icon} {T(m.title)}</option>)}
            </select>
          </div>
          {selMod && (
            <div style={{ marginBottom: 16 }}>
              <label style={{ display: "block", fontSize: 10, color: "#4a6080", letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 6 }}>{lang === "en" ? "Lesson" : "บทเรียน"}</label>
              <select value={selectedLesson} onChange={e => setSelectedLesson(e.target.value)}
                style={{ width: "100%", padding: "9px 12px", background: "#0a0f1a", border: "1px solid #1a3060", borderRadius: 6, color: selectedLesson ? "#c9d8f0" : "#4a6080", fontSize: 14, outline: "none" }}>
                <option value="">{lang === "en" ? "— Select lesson —" : "— เลือกบทเรียน —"}</option>
                {selMod.lessons.map(l => <option key={l.id} value={l.id}>{T(l.title)}</option>)}
              </select>
            </div>
          )}
          <button onClick={startInterview} disabled={!canStart}
            style={{ padding: "10px 24px", background: canStart ? "#1a4080" : "#111", border: `1px solid ${canStart ? "#2a60c0" : "#1a3060"}`, borderRadius: 6, color: canStart ? "#93c5fd" : "#2a4060", fontWeight: 700, fontSize: 14, cursor: canStart ? "pointer" : "not-allowed" }}>
            🎙 {lang === "en" ? "Start Interview" : "เริ่มสัมภาษณ์"}
          </button>
        </div>
      )}

      {screen === "interview" && (
        <div style={{ display: "flex", flexDirection: "column", height: 420 }}>
          <div style={{ flex: 1, overflowY: "auto", padding: "14px 20px", display: "flex", flexDirection: "column", gap: 10 }}>
            {messages.map((m, i) => (
              <div key={i} style={{ display: "flex", justifyContent: m.role === "user" ? "flex-end" : "flex-start" }}>
                <div style={{ maxWidth: "80%", padding: "10px 14px", borderRadius: m.role === "user" ? "12px 12px 3px 12px" : "12px 12px 12px 3px", background: m.role === "user" ? "#1a3060" : "#0e1420", border: `1px solid ${m.role === "user" ? "#2a5090" : "#1a2a40"}`, fontSize: 13, color: "#c9d8f0", lineHeight: 1.6, whiteSpace: "pre-wrap" }}>
                  {m.content}
                </div>
              </div>
            ))}
            {loading && <div style={{ color: "#4a6080", fontSize: 13, padding: "4px 0" }}>● ● ●</div>}
            <div ref={chatEndRef} />
          </div>
          <div style={{ display: "flex", gap: 10, padding: "12px 20px", borderTop: "1px solid #1a3060", background: "#0a0f1a" }}>
            <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && !e.shiftKey && sendMessage()} placeholder={lang === "en" ? "Type your response…" : "พิมพ์คำตอบ…"}
              style={{ flex: 1, padding: "9px 14px", background: "#0d1525", border: "1px solid #1a3060", borderRadius: 6, color: "#c9d8f0", fontSize: 14, outline: "none" }} />
            <button onClick={sendMessage} disabled={loading || !input.trim()}
              style={{ padding: "9px 18px", background: loading || !input.trim() ? "#111" : "#1a4080", border: "1px solid #2a5090", borderRadius: 6, color: "#93c5fd", fontWeight: 600, fontSize: 13, cursor: loading || !input.trim() ? "not-allowed" : "pointer" }}>
              {lang === "en" ? "Send" : "ส่ง"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function DashboardView({ lang, setLang, user, users, modules, getStatus, getUserTotals, isModuleLocked, T, G, theme, setTheme, font, setFont, customRoles, onLesson, onLogout, onSpecialist, specialistProgress, onSubmitAiSuggestion, announcements, onLikeAnnouncement, onDeleteAnnouncement, onCreateAnnouncement, notifications, onMarkNotificationRead, onMarkAllNotificationsRead }) {
  const { done, total, pct, avgScore } = getUserTotals(user.email);
  const days = daysLeft(user.joinDate);
  const dColor = deadlineColor(days);
  const isComplete = pct === 100;
  // Calculate remaining time from actual content word count + quiz length per incomplete lesson
  const remaining = (() => {
    let mins = 0;
    modules.forEach(mod => {
      mod.lessons.forEach(l => {
        if (getStatus(user.email, mod.id, l.id)?.completed) return;
        const wordCount = (l.content?.en || "").split(/\s+/).filter(Boolean).length;
        const readMins = Math.ceil(wordCount / 180); // ~180 wpm reading speed for learning content
        const quizMins = Math.ceil((l.quiz?.length || 0) * 1.5); // ~1.5 min per quiz question
        mins += Math.max(readMins + quizMins, 5); // minimum 5 min per lesson
      });
    });
    return mins;
  })();
  const remainHours = Math.floor(remaining / 60);
  const remainMins = remaining % 60;

  // Next recommended lesson — first incomplete in an unlocked module
  let nextLesson = null;
  for (const mod of modules) {
    if (isModuleLocked(mod, user.email)) continue;
    for (const lesson of mod.lessons) {
      if (!getStatus(user.email, mod.id, lesson.id)?.completed) { nextLesson = { mod, lesson }; break; }
    }
    if (nextLesson) break;
  }

  return (
    <div>
      <header style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 20px", borderBottom: `1px solid ${G.border}`, background: G.headerBg, position: "sticky", top: 0, zIndex: 50, boxShadow: G.shadow, flexWrap: "wrap", gap: 8 }}>
        <img src={LOGO} alt="" style={{ height: 28, flexShrink: 0, filter: G.mode === "light" ? "invert(1) sepia(0.2)" : "none" }} />
        <div style={{ display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap", minWidth: 0 }}>
          <ThemeToggle theme={theme} setTheme={setTheme} G={G} />
          <FontSelector font={font} setFont={setFont} G={G} />
          <button onClick={() => setLang(lang === "en" ? "th" : "en")} style={{ padding: "4px 10px", background: "transparent", border: `1px solid ${G.border}`, borderRadius: 20, color: G.muted, fontSize: 12, whiteSpace: "nowrap" }}>
            {lang === "en" ? "TH" : "EN"}
          </button>
          <span style={{ fontSize: 12, color: G.muted, whiteSpace: "nowrap", maxWidth: 130, overflow: "hidden", textOverflow: "ellipsis" }}>👤 {user.name.split(" ")[0]}</span>
          <NotificationBell notifications={notifications || []} onMarkRead={onMarkNotificationRead} onMarkAllRead={onMarkAllNotificationsRead} G={G} lang={lang} />
          <button onClick={onLogout} style={{ padding: "4px 10px", background: "transparent", border: `1px solid ${G.border}`, borderRadius: 6, color: G.muted, fontSize: 12, whiteSpace: "nowrap" }}>
            {lang === "en" ? "Sign Out" : "ออก"}
          </button>
        </div>
      </header>

      {/* Hero Stats Bar */}
      <div style={{ background: G.card, borderBottom: `1px solid ${G.border}`, padding: "24px 28px" }}>
        <div style={{ maxWidth: 1060, margin: "0 auto" }}>
          <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: 20, flexWrap: "wrap", gap: 12 }}>
            <div>
              <h2 style={{ fontSize: 26, fontWeight: 600, color: G.goldLight, letterSpacing: "0.06em" }}>
                {lang === "en" ? `Welcome back, ${user.name.split(" ")[0]}` : `ยินดีต้อนรับ ${user.name.split(" ")[0]}`}
              </h2>
              {user.department && <p style={{ fontSize: 13, color: G.muted, marginTop: 4 }}>{user.department}{user.employeeId ? ` · ${user.employeeId}` : ""}</p>}
              {/* Specialist badges mini row */}
              {(() => {
                const earned = typeof specialistProgress === "object"
                  ? Object.entries(specialistProgress).filter(([k,v]) => v?.certified && k.startsWith(user.email + "_")).map(([k]) => {
                      const trackId = k.replace(user.email + "_","");
                      return (typeof SPECIALIST_TRACKS !== "undefined" ? SPECIALIST_TRACKS : []).find(t => t.id === trackId);
                    }).filter(Boolean)
                  : [];
                if (!earned.length) return null;
                return (
                  <div style={{ display: "flex", gap: 6, marginTop: 8, flexWrap: "wrap" }}>
                    {earned.map(t => (
                      <div key={t.id} title={`${t.brand} Specialist`}
                        style={{ width: 28, height: 28, borderRadius: "50%", background: `${t.color}22`, border: `1.5px solid ${t.color}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>
                        {t.icon}
                      </div>
                    ))}
                    <span style={{ fontSize: 11, color: G.gold, alignSelf: "center" }}>{lang === "en" ? "Specialist" : "ผู้เชี่ยวชาญ"}</span>
                  </div>
                );
              })()}
            </div>
            {!isComplete ? (
              <div style={{ padding: "10px 18px", background: G.inputBg, border: `1px solid ${dColor}33`, borderRadius: 8, textAlign: "center" }}>
                <div style={{ fontSize: 22, fontWeight: 700, color: dColor }}>{days}</div>
                <div style={{ fontSize: 10, color: G.muted, letterSpacing: "0.1em", textTransform: "uppercase" }}>{lang === "en" ? "Days Left" : "วันที่เหลือ"}</div>
                {days <= 7 && <div style={{ fontSize: 10, color: dColor, marginTop: 2 }}>⚠ {lang === "en" ? "Deadline approaching" : "ใกล้ครบกำหนด"}</div>}
              </div>
            ) : (
              <div style={{ padding: "10px 18px", background: "#0a1a0a", border: "1px solid #1a4a1a", borderRadius: 8, textAlign: "center" }}>
                <div style={{ fontSize: 22 }}>🏆</div>
                <div style={{ fontSize: 10, color: "#4ade80", letterSpacing: "0.1em", textTransform: "uppercase" }}>{lang === "en" ? "Certified!" : "สำเร็จ!"}</div>
              </div>
            )}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(150px, 1fr))", gap: 12, marginBottom: 20 }}>
            {[
              { icon: "📚", val: `${done}/${total}`, label: lang === "en" ? "Lessons Done" : "บทเรียนสำเร็จ" },
              { icon: "📊", val: `${pct}%`, label: lang === "en" ? "Completed" : "สำเร็จ" },
              { icon: "⭐", val: `${avgScore}%`, label: lang === "en" ? "Avg Score" : "คะแนนเฉลี่ย" },
              { icon: "⏱", val: remaining === 0 ? (lang === "en" ? "Done! 🎉" : "สำเร็จ! 🎉") : (remainHours > 0 ? `${remainHours}h ${remainMins}m` : `${remainMins}m`), label: lang === "en" ? "Est. Remaining" : "เหลืออีกประมาณ" },
            ].map((s, i) => (
              <div key={i} style={{ background: G.card, border: `1px solid ${G.border}`, borderRadius: 8, padding: "14px 16px", textAlign: "center" }}>
                <div style={{ fontSize: 18, marginBottom: 4 }}>{s.icon}</div>
                <div style={{ fontSize: 20, fontWeight: 700, color: G.gold }}>{s.val}</div>
                <div style={{ fontSize: 10, color: G.muted, marginTop: 2, letterSpacing: "0.06em" }}>{s.label}</div>
              </div>
            ))}
          </div>
          <div>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
              <span style={{ fontSize: 11, color: G.muted, letterSpacing: "0.1em", textTransform: "uppercase" }}>{lang === "en" ? "Overall Progress" : "ความคืบหน้าโดยรวม"}</span>
              <span style={{ fontSize: 12, color: G.gold, fontWeight: 600 }}>{pct}%</span>
            </div>
            <div style={{ height: 6, background: "#1a1a1a", borderRadius: 3 }}>
              <div style={{ height: "100%", width: `${pct}%`, background: isComplete ? "#4ade80" : `linear-gradient(90deg, ${G.gold}, ${G.goldLight})`, borderRadius: 3, transition: "width 0.6s ease" }} />
            </div>
          </div>
        </div>
      </div>

      <main style={{ maxWidth: 1060, margin: "0 auto", padding: "32px 24px" }}>
        {/* Next Up Card */}
        {nextLesson && (
          <div style={{ background: "linear-gradient(135deg, #111 0%, #151208 100%)", border: `1px solid ${G.gold}33`, borderRadius: 10, padding: "18px 24px", marginBottom: 28, display: "flex", alignItems: "center", gap: 20, flexWrap: "wrap", animation: "fadeUp 0.3s ease" }}>
            <div style={{ fontSize: 32 }}>▶️</div>
            <div style={{ flex: 1, minWidth: 160 }}>
              <div style={{ fontSize: 10, color: G.gold, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 4 }}>{lang === "en" ? "Continue where you left off" : "เรียนต่อจากที่หยุด"}</div>
              <div style={{ fontSize: 17, color: G.goldLight }}>{T(nextLesson.lesson.title)}</div>
              <div style={{ fontSize: 12, color: G.muted, marginTop: 2 }}>{nextLesson.mod.icon} {T(nextLesson.mod.title)} · ~15 {lang === "en" ? "min" : "นาที"}</div>
            </div>
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              <button onClick={() => onLesson(nextLesson.mod.id, nextLesson.lesson.id, true)}
                style={{ padding: "10px 18px", background: "transparent", border: `1px solid ${G.gold}`, borderRadius: 6, color: G.gold, fontWeight: 600, fontSize: 12, letterSpacing: "0.06em", whiteSpace: "nowrap" }}>
                ⚡ {lang === "en" ? "Pre-Quiz" : "ทดสอบก่อน"}
              </button>
              <button onClick={() => onLesson(nextLesson.mod.id, nextLesson.lesson.id)}
                style={{ padding: "10px 20px", background: G.gold, border: "none", borderRadius: 6, color: "#0c0c0c", fontWeight: 700, fontSize: 13, whiteSpace: "nowrap" }}>
                {lang === "en" ? "Study →" : "เรียน →"}
              </button>
            </div>
          </div>
        )}

        {/* Module Grid */}
        {/* Specialist Centre entry card */}
        {(() => {
          const earnedCount = typeof specialistProgress === "object"
            ? Object.values(specialistProgress).filter(v => v && v.certified).length
            : 0;
          return (
            <div onClick={onSpecialist}
              style={{ background: "linear-gradient(135deg, #0c0c0c 0%, #151208 60%, #1a1408 100%)", border: `1px solid ${G.gold}40`, borderRadius: 12, padding: "20px 24px", marginBottom: 28, cursor: "pointer", display: "flex", alignItems: "center", gap: 20, flexWrap: "wrap", position: "relative", overflow: "hidden" }}
              onMouseEnter={e => e.currentTarget.style.borderColor = G.gold + "80"}
              onMouseLeave={e => e.currentTarget.style.borderColor = G.gold + "40"}>
              <div style={{ position: "absolute", right: 20, top: "50%", transform: "translateY(-50%)", fontSize: 80, opacity: 0.05 }}>🎖️</div>
              <div style={{ fontSize: 40 }}>🎖️</div>
              <div style={{ flex: 1, minWidth: 180 }}>
                <div style={{ fontSize: 10, color: G.gold, letterSpacing: "0.14em", textTransform: "uppercase", marginBottom: 4 }}>
                  {lang === "en" ? "Brand Specialist Certification" : "การรับรองผู้เชี่ยวชาญแบรนด์"}
                </div>
                <div style={{ fontSize: 18, color: G.goldLight, fontWeight: 700 }}>
                  {lang === "en" ? "Specialist Centre" : "ศูนย์ผู้เชี่ยวชาญ"}
                </div>
                <div style={{ fontSize: 13, color: G.muted, marginTop: 4, lineHeight: 1.5 }}>
                  {lang === "en"
                    ? "Deep-dive into individual brands. Earn specialist badges for ELMES, FritsJurgens, SIMONSWERK and more."
                    : "เรียนรู้เชิงลึกในแต่ละแบรนด์ รับเหรียญผู้เชี่ยวชาญสำหรับ ELMES, FritsJurgens, SIMONSWERK และอื่นๆ"}
                </div>
              </div>
              <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 4, flexShrink: 0 }}>
                {earnedCount > 0 && (
                  <div style={{ padding: "4px 12px", background: G.gold + "22", border: `1px solid ${G.gold}`, borderRadius: 20, color: G.gold, fontSize: 12, fontWeight: 700 }}>
                    🏅 {earnedCount} {lang === "en" ? "Earned" : "ได้รับ"}
                  </div>
                )}
                <div style={{ color: G.gold, fontSize: 22 }}>→</div>
              </div>
            </div>
          );
        })()}

        {/* Knowledge Interview card — shown to Specialist role users and any user with ai_interview permission */}
        {(hasPermission(user, "ai_interview", customRoles) || ["specialist"].includes((user.roleId || user.role)?.toLowerCase())) && onSubmitAiSuggestion && (
          <SpecialistInterviewCard lang={lang} user={user} modules={modules} T={T} G={G} onSubmit={onSubmitAiSuggestion} />
        )}

        {/* Announcements / NPD widget */}
        <AnnouncementsWidget lang={lang} announcements={announcements || []} currentUser={user} G={G} customRoles={customRoles}
          onLike={onLikeAnnouncement} onDelete={onDeleteAnnouncement} onCreate={onCreateAnnouncement} />

        {/* Training Leaderboard widget */}
        {users && Object.keys(users).length > 1 && (
          <LeaderboardWidget lang={lang} users={users} getUserTotals={getUserTotals} currentUserEmail={user.email} G={G} />
        )}

        {/* Specialist Leaderboard — visible when users data is available */}
        {users && Object.keys(users).length > 1 && specialistProgress && Object.keys(specialistProgress).length > 0 && (
          <SpecialistLeaderboard lang={lang} users={users} specialistProgress={specialistProgress} currentUserEmail={user.email} G={G} />
        )}

        <h3 style={{ fontSize: 11, color: G.muted, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 20 }}>
          {lang === "en" ? "All Training Modules" : "โมดูลการฝึกอบรมทั้งหมด"}
        </h3>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 16 }}>
          {modules.map((mod, i) => {
            const locked = isModuleLocked(mod, user.email);
            const mDone = mod.lessons.filter(l => getStatus(user.email, mod.id, l.id)?.completed).length;
            const mPct = Math.round((mDone / mod.lessons.length) * 100);
            const mComplete = mPct === 100;

            // What modules are required?
            const reqNames = (mod.unlockAfter || []).map(rid => modules.find(m => m.id === rid)?.title?.en || rid);

            return (
              <div key={mod.id} style={{ background: G.card, border: `1px solid ${locked ? "#2a2a2a" : mComplete ? "#1a3a1a" : G.border}`, borderRadius: 10, overflow: "hidden", opacity: locked ? 0.6 : 1, animation: `fadeUp 0.3s ease ${i * 0.04}s both`, position: "relative" }}>
                {/* Lock overlay banner */}
                {locked && (
                  <div style={{ position: "absolute", top: 0, left: 0, right: 0, background: "#111", borderBottom: "1px solid #2a2a2a", padding: "6px 14px", display: "flex", alignItems: "center", gap: 6, zIndex: 2 }}>
                    <span style={{ fontSize: 12 }}>🔒</span>
                    <span style={{ fontSize: 11, color: "#555" }}>
                      {lang === "en" ? `Complete first: ${reqNames.join(", ")}` : `ต้องสำเร็จก่อน: ${reqNames.join(", ")}`}
                    </span>
                  </div>
                )}
                <div style={{ padding: locked ? "40px 18px 12px" : "16px 18px 12px", borderBottom: `1px solid ${G.border}` }}>
                  <div style={{ display: "flex", alignItems: "flex-start", gap: 12, marginBottom: 12 }}>
                    <span style={{ fontSize: 24, lineHeight: 1 }}>{locked ? "🔒" : mod.icon}</span>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 14, fontWeight: 600, color: locked ? G.muted : mComplete ? "#86efac" : G.goldLight }}>{T(mod.title)}</div>
                      <div style={{ fontSize: 11, color: G.muted, marginTop: 2 }}>{T(mod.desc)}</div>
                    </div>
                    {mComplete && <span style={{ fontSize: 16 }}>✅</span>}
                  </div>
                  {!locked && (
                    <>
                      <div style={{ height: 3, background: "#1a1a1a", borderRadius: 2 }}>
                        <div style={{ height: "100%", width: `${mPct}%`, background: mComplete ? "#4ade80" : G.gold, borderRadius: 2, transition: "width 0.5s" }} />
                      </div>
                      <div style={{ fontSize: 10, color: G.muted, marginTop: 6 }}>{mDone}/{mod.lessons.length} {lang === "en" ? "lessons" : "บทเรียน"}</div>
                    </>
                  )}
                </div>
                {!locked && (
                  <div style={{ padding: "8px 0" }}>
                    {mod.lessons.map(lesson => {
                      const s = getStatus(user.email, mod.id, lesson.id);
                      const scorePct = s?.score !== undefined ? Math.round((s.score / lesson.quiz.length) * 100) : null;
                      return (
                        <div key={lesson.id} style={{ display: "flex", alignItems: "center", borderBottom: `1px solid ${G.border}10` }}>
                          <button onClick={() => onLesson(mod.id, lesson.id)}
                            style={{ flex: 1, display: "flex", justifyContent: "space-between", alignItems: "center", padding: "9px 14px 9px 18px", background: "transparent", border: "none", color: "inherit", textAlign: "left", transition: "background 0.15s" }}
                            onMouseEnter={e => e.currentTarget.style.background = "#1a1a1a"}
                            onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
                            <span style={{ display: "flex", alignItems: "center", gap: 8 }}>
                              <span style={{ fontSize: 13, color: s?.completed ? "#4ade80" : "#444" }}>{s?.completed ? "✓" : "○"}</span>
                              <span style={{ fontSize: 13, color: s?.completed ? "#aaa" : "#666" }}>{T(lesson.title)}</span>
                              {s?.skippedLesson && <span style={{ fontSize: 9, color: G.gold, border: `1px solid ${G.gold}55`, borderRadius: 3, padding: "1px 5px", letterSpacing: "0.05em" }}>PRE-QUIZ</span>}
                            </span>
                            {s?.completed && scorePct !== null && (
                              <span style={{ fontSize: 11, color: scorePct >= 90 ? "#4ade80" : scorePct >= 70 ? G.gold : "#f87171", whiteSpace: "nowrap" }}>{scorePct}%</span>
                            )}
                          </button>
                          {/* Pre-quiz button per lesson */}
                          {!s?.completed && (
                            <button onClick={() => onLesson(mod.id, lesson.id, true)}
                              title={lang === "en" ? "Take pre-quiz to skip lesson content" : "ทดสอบก่อนเพื่อข้ามเนื้อหา"}
                              style={{ padding: "9px 10px", background: "transparent", border: "none", color: "#333", fontSize: 12, flexShrink: 0 }}
                              onMouseEnter={e => e.currentTarget.style.color = G.gold}
                              onMouseLeave={e => e.currentTarget.style.color = "#333"}>
                              ⚡
                            </button>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Learning path legend */}
        <div style={{ marginTop: 28, padding: "12px 16px", background: G.inputBg, border: `1px solid ${G.border}`, borderRadius: 8, display: "flex", gap: 24, flexWrap: "wrap", fontSize: 11, color: G.muted }}>
          <span>⚡ {lang === "en" ? "Pre-quiz: already know it? Skip the reading and just take the quiz." : "Pre-quiz: รู้แล้ว? ข้ามเนื้อหาและทำแบบทดสอบทันที"}</span>
          <span>🔒 {lang === "en" ? "Locked: complete prerequisite modules to unlock." : "ล็อค: สำเร็จโมดูลที่กำหนดเพื่อปลดล็อค"}</span>
        </div>
      </main>
    </div>
  );
}

