function EditUserModal({ user, G, lang, customRoles, onSave, onClose }) {
  const roles = (customRoles || DEFAULT_ROLES).map(r => r.label);
  const [form, setForm] = useState({
    name: user.name || "", email: user.email || "",
    employeeId: user.employeeId || "", department: user.department || "",
    role: user.role || "Sales Executive", password: ""
  });
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const [err, setErr] = useState("");
  const submit = () => {
    if (!form.name || !form.email) return setErr(lang === "en" ? "Name and email are required." : "ต้องกรอกชื่อและอีเมล");
    if (form.password && form.password.length < 6) return setErr(lang === "en" ? "New password must be 6+ characters." : "รหัสผ่านใหม่ต้องมีอย่างน้อย 6 ตัวอักษร");
    setErr(""); onSave(user.email, form);
  };
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.75)", zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center" }} onClick={onClose}>
      <div style={{ background: "#111", border: `1px solid ${G.border}`, borderRadius: 12, padding: 28, width: "100%", maxWidth: 500, maxHeight: "90vh", overflowY: "auto" }} onClick={e => e.stopPropagation()}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <h3 style={{ fontSize: 16, fontWeight: 500, color: G.goldLight }}>✏️ {lang === "en" ? "Edit User" : "แก้ไขผู้ใช้"}</h3>
          <button onClick={onClose} style={{ background: "transparent", border: "none", color: G.muted, fontSize: 20, cursor: "pointer" }}>✕</button>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
          {[
            { key: "name", label: { en: "Full Name *", th: "ชื่อ-นามสกุล *" }, ph: "Jane Smith" },
            { key: "email", label: { en: "Email / Username *", th: "อีเมล *" }, ph: "jane@ts2100.com" },
            { key: "employeeId", label: { en: "Employee ID", th: "รหัสพนักงาน" }, ph: "TS-005" },
            { key: "department", label: { en: "Department", th: "แผนก" }, ph: "Sales" },
            { key: "password", label: { en: "New Password", th: "รหัสผ่านใหม่" }, ph: lang === "en" ? "Leave blank to keep current" : "เว้นว่างเพื่อคงเดิม", type: "password" },
          ].map(f => (
            <div key={f.key} style={{ gridColumn: f.key === "name" || f.key === "email" ? "span 1" : "span 1" }}>
              <label style={{ display: "block", fontSize: 10, color: G.muted, letterSpacing: "0.08em", textTransform: "uppercase", marginBottom: 6 }}>{f.label[lang]}</label>
              <input type={f.type || "text"} value={form[f.key]} onChange={e => set(f.key, e.target.value)} placeholder={f.ph}
                style={{ width: "100%", padding: "9px 12px", background: G.inputBg, border: `1px solid ${G.border}`, borderRadius: 6, color: G.text, fontSize: 14, outline: "none", boxSizing: "border-box" }} />
            </div>
          ))}
          <div>
            <label style={{ display: "block", fontSize: 10, color: G.muted, letterSpacing: "0.08em", textTransform: "uppercase", marginBottom: 6 }}>{lang === "en" ? "Role" : "ตำแหน่ง"}</label>
            <select value={form.role} onChange={e => set("role", e.target.value)}
              style={{ width: "100%", padding: "9px 12px", background: G.inputBg, border: `1px solid ${G.border}`, borderRadius: 6, color: G.text, fontSize: 14, outline: "none" }}>
              {roles.map(r => <option key={r}>{r}</option>)}
            </select>
          </div>
        </div>
        {err && <p style={{ color: "#f87171", fontSize: 13, marginTop: 10 }}>{err}</p>}
        <div style={{ display: "flex", gap: 10, marginTop: 20 }}>
          <button onClick={submit} style={{ flex: 1, padding: "10px 0", background: G.gold, border: "none", borderRadius: 6, color: "#0c0c0c", fontWeight: 700, fontSize: 14 }}>
            {lang === "en" ? "Save Changes" : "บันทึก"}
          </button>
          <button onClick={onClose} style={{ padding: "10px 20px", background: "transparent", border: `1px solid ${G.border}`, borderRadius: 6, color: G.muted, fontSize: 14 }}>
            {lang === "en" ? "Cancel" : "ยกเลิก"}
          </button>
        </div>
      </div>
    </div>
  );
}

