// ─── BLOCK EDITOR HELPERS ─────────────────────────────────────────────────────
// Block types: text | heading | bullet | image | video | divider
function emptyBlock(type = "text") {
  return { id: Date.now() + Math.random(), type, en: "", th: "", url: "" };
}

// Convert legacy markdown string → blocks array (best-effort)
function legacyToBlocks(str) {
  if (!str) return [emptyBlock("text")];
  const lines = str.split("\n");
  const blocks = [];
  for (const line of lines) {
    if (!line.trim()) continue;
    const clean = line.replace(/\*\*(.*?)\*\*/g, "$1"); // strip bold markers
    if (line.startsWith("• ") || line.startsWith("- ")) {
      blocks.push({ ...emptyBlock("bullet"), en: clean.replace(/^[•-]\s*/, "") });
    } else {
      blocks.push({ ...emptyBlock("text"), en: clean });
    }
  }
  return blocks.length ? blocks : [emptyBlock("text")];
}

// Convert blocks → plain text for backward-compat rendering in LessonView
function blocksToLegacy(blocks) {
  return blocks.map(b => {
    if (b.type === "bullet") return `• ${b.en}`;
    if (b.type === "heading") return `**${b.en}**`;
    if (b.type === "divider") return "---";
    return b.en;
  }).join("\n");
}

// Single block editor row
